import { FileSystemNode } from "../types";

// User provided credentials
const SUPABASE_URL = "https://dczhrnenedtudwultavb.supabase.co";
const SUPABASE_KEY = "sb_publishable_il4BNoTUPPax231p-mJ-Vg_WhD8QkCO";

export const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

/**
 * Persistence Strategy:
 * We store the entire FileSystemNode tree in a single JSONB column.
 * Table: 'sosa_data'
 * Columns: 'key' (text, primary key), 'data' (jsonb)
 * Row Key: 'file_system'
 * 
 * NOTE: Ensure you have created this table in your Supabase SQL Editor:
 * 
 * create table sosa_data (
 *   key text primary key,
 *   data jsonb
 * );
 */

export const saveNodesToSupabase = async (nodes: Record<string, FileSystemNode>) => {
  try {
    const { error } = await supabase
      .from('sosa_data')
      .upsert({ key: 'file_system', data: nodes }, { onConflict: 'key' });

    if (error) {
      console.warn('Supabase Save Error (check if table "sosa_data" exists):', error.message);
    }
  } catch (e) {
    console.error('Unexpected Supabase Error:', e);
  }
};

export const loadNodesFromSupabase = async (): Promise<Record<string, FileSystemNode> | null> => {
  try {
    const { data, error } = await supabase
      .from('sosa_data')
      .select('data')
      .eq('key', 'file_system')
      .single();

    if (error) {
      // If code 'PGRST116' (row not found) or '42P01' (table not found)
      console.log('Supabase Load Status:', error.message);
      return null;
    }
    return data?.data as Record<string, FileSystemNode>;
  } catch (e) {
    console.error('Unexpected Supabase Load Error:', e);
    return null;
  }
};

