/**
 * Persistence Strategy:
 * We store the entire FileSystemNode tree in a single JSONB column.
 * Table: 'sosa_data'
 * Columns: 'key' (text, primary key), 'data' (jsonb)
 * Row Key: 'file_system'
 */

// --- DATA PERSISTENCE ---

export const saveNodesToSupabase = async (nodes: Record<string, FileSystemNode>) => {
  try {
    // Basic check to ensure we don't save if not logged in
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return;

    // In a real app with multi-tenancy, 'file_system' would be scoped to user_id or workspace_id
    const { error } = await supabase
      .from('sosa_data')
      .upsert({ key: 'file_system', data: nodes }, { onConflict: 'key' });

    if (error) {
      console.warn('Supabase Save Error (check if table "sosa_data" exists):', error.message);
    }
  } catch (e) {
    console.error('Unexpected Supabase Error:', e);
  }
};

export const loadNodesFromSupabase = async (): Promise<Record<string, FileSystemNode> | null> => {
  try {
    const { data, error } = await supabase
      .from('sosa_data')
      .select('data')
      .eq('key', 'file_system')
      .single();

    if (error) {
      console.log('Supabase Load Status:', error.message);
      return null;
    }
    return data?.data as Record<string, FileSystemNode>;
  } catch (e) {
    console.error('Unexpected Supabase Load Error:', e);
    return null;
  }
};

// --- AUTH & PROFILE ---

export const getUserProfile = async (userId: string): Promise<UserProfile | null> => {
  const { data, error } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', userId)
    .single();

  if (error) {
    console.warn('Error fetching profile:', error.message);
    return null;
  }
  return data as UserProfile;
};

export const updateUserProfile = async (userId: string, updates: Partial<UserProfile>) => {
  const { error } = await supabase
    .from('profiles')
    .upsert({ id: userId, ...updates, updated_at: new Date().toISOString() });

  if (error) throw error;
};

export const createBrand = async (brandData: Partial<Brand>) => {
  const { error } = await supabase
    .from('brands')
    .insert([brandData]);

  if (error) throw error;
};

export const signOut = async () => {
  await supabase.auth.signOut();
};

