import React, { useState, useRef, useEffect } from 'react';
import { FileSystemNode, NodeType, UserProfile, Brand } from '../types';
import { soundService } from '../services/soundService';
import { signOut } from '../services/supabase';
import { 
  ChevronRight, 
  ChevronDown, 
  Folder, 
  LayoutTemplate, 
  Search, 
  Plus,
  MoreHorizontal,
  Star,
  Clock,
  Home,
  Trash2,
  Edit2,
  Volume2,
  VolumeX,
  LogOut,
  User as UserIcon
} from 'lucide-react';

interface SidebarProps {
  nodes: Record<string, FileSystemNode>;
  activeNodeId: string;
  userProfile?: UserProfile | null;
  brand?: Brand | null;
  onNavigate: (id: string) => void;
  onToggleExpand: (id: string) => void;
  onCreateNode: (type: NodeType, parentId: string | null) => void;
  onToggleFavorite: (id: string) => void;
  onMoveNode: (dragId: string, targetId: string) => void;
  onUpdateNode: (id: string, updates: Partial<FileSystemNode>) => void;
  onDeleteNode: (id: string) => void;
}

const EMOJI_LIST = [
  '📁', '📂', '📄', '📝', '📊', '📈', '🎨', '🖼️', 
  '📅', '🗓️', '🚀', '💡', '🎯', '🔥', '✅', '⚠️', 
  '🔴', '🔵', '🟢', '💼', '🏠', '⭐️', '❤️'
];

export const Sidebar: React.FC<SidebarProps> = ({
  nodes,
  activeNodeId,
  userProfile,
  brand,
  onNavigate,
  onToggleExpand,
  onCreateNode,
  onToggleFavorite,
  onMoveNode,
  onUpdateNode,
  onDeleteNode
}) => {
  const [searchTerm, setSearchTerm] = useState("");
  const [draggedNodeId, setDraggedNodeId] = useState<string | null>(null);

  // --- Interaction States ---
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState("");
  const editInputRef = useRef<HTMLInputElement>(null);

  const [activeMenuId, setActiveMenuId] = useState<string | null>(null);
  const [activeEmojiId, setActiveEmojiId] = useState<string | null>(null);
  const [showProfileMenu, setShowProfileMenu] = useState(false);

  // --- Sound State ---
  const [isMuted, setIsMuted] = useState(soundService.getMuteState());

  const handleToggleSound = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newState = soundService.toggleMute();
    setIsMuted(newState);
  };

  useEffect(() => {
    const handleClickOutside = () => {
      setActiveMenuId(null);
      setActiveEmojiId(null);
      setShowProfileMenu(false);
    };
    window.addEventListener('click', handleClickOutside);
    return () => window.removeEventListener('click', handleClickOutside);
  }, []);

  useEffect(() => {
    if (editingId && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select();
    }
  }, [editingId]);

  // --- Helpers ---
  const getRootNodes = () => (Object.values(nodes) as FileSystemNode[]).filter(n => n.parentId === null);
  const getChildren = (parentId: string) => (Object.values(nodes) as FileSystemNode[]).filter(n => n.parentId === parentId);

  // --- Identity Logic ---
  const displayName = brand?.name || userProfile?.full_name || 'My Workspace';
  const displaySubtitle = brand ? 'Team Plan' : (userProfile?.account_type === 'team' ? 'Team Plan' : 'Individual');
  const avatarUrl = brand?.logo_url || userProfile?.avatar_url;
  const initials = displayName.substring(0, 2).toUpperCase();

  // --- Actions ---
  const startRenaming = (e: React.MouseEvent, node: FileSystemNode) => {
    e.stopPropagation();
    setActiveMenuId(null);
    setEditingId(node.id);
    setEditValue(node.name);
  };

  const finishRenaming = () => {
    if (editingId && editValue.trim()) {
      onUpdateNode(editingId, { name: editValue.trim() });
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') finishRenaming();
    if (e.key === 'Escape') setEditingId(null);
  };

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setActiveMenuId(activeMenuId === id ? null : id);
    setActiveEmojiId(null);
  };

  const toggleEmojiPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setActiveEmojiId(activeEmojiId === id ? null : id);
    setActiveMenuId(null);
  };

  const selectEmoji = (id: string, emoji: string) => {
    onUpdateNode(id, { icon: emoji });
    setActiveEmojiId(null);
  };

  const handleSignOut = () => {
    signOut();
    window.location.reload();
  };

  // --- Drag & Drop ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
    if (editingId) {
      e.preventDefault();
      return;
    }
    setDraggedNodeId(id);
    e.dataTransfer.setData('nodeId', id);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: React.DragEvent, targetNode: FileSystemNode) => {
    e.preventDefault();
    if (targetNode.type !== 'whiteboard') {
      e.dataTransfer.dropEffect = 'move';
    }
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
    e.preventDefault();
    const dragId = e.dataTransfer.getData('nodeId');
    if (dragId && dragId !== targetId) {
      onMoveNode(dragId, targetId);
      soundService.play('drop'); // Sound Feedback
    }
    setDraggedNodeId(null);
  };

  // --- Recursive Tree Item ---
  const TreeItem: React.FC<{ nodeId: string; depth?: number }> = ({ nodeId, depth = 0 }) => {
    const node = nodes[nodeId];
    if (!node) return null;

    if (searchTerm && !node.name.toLowerCase().includes(searchTerm.toLowerCase())) {
        const children = getChildren(nodeId);
        const hasMatchingChild = children.some(c => c.name.toLowerCase().includes(searchTerm.toLowerCase()));
        if (!hasMatchingChild) return null;
    }

    const children = getChildren(nodeId);
    const hasChildren = children.length > 0;
    const isExpanded = node.isExpanded || searchTerm.length > 0;
    const isActive = activeNodeId === nodeId;
    const isEditing = editingId === nodeId;

    const getIcon = () => {
      if (node.icon) return <span className="text-[14px] leading-none">{node.icon}</span>;
      if (node.type === 'folder' || node.type === 'page') return <Folder size={14} className={isActive ? "text-[#3A5C34]" : "text-gray-400"} fill={isActive ? "currentColor" : "none"} />;
      return <LayoutTemplate size={14} className={isActive ? "text-[#3A5C34]" : "text-gray-400"} />;
    };

    return (
      <div className="select-none relative">
        <div 
          className={`
            group flex items-center gap-2 py-1.5 px-2 mx-2 rounded-lg cursor-pointer text-[13px] transition-all relative
            ${isActive ? 'bg-[#3A5C34]/10 text-[#3A5C34] font-medium' : 'text-gray-600 hover:bg-[#FCCAE2]/20 hover:text-gray-900'}
            ${draggedNodeId === nodeId ? 'opacity-50' : ''}
          `}
          style={{ paddingLeft: `${depth * 16 + 8}px` }}
          onClick={() => !isEditing && onNavigate(nodeId)}
          draggable={!isEditing}
          onDragStart={(e) => handleDragStart(e, nodeId)}
          onDragOver={(e) => handleDragOver(e, node)}
          onDrop={(e) => handleDrop(e, nodeId)}
        >
          {/* Chevron */}
          <div 
            className={`w-4 h-4 flex items-center justify-center rounded hover:bg-black/5 text-gray-400 transition-colors ${!hasChildren && node.type === 'whiteboard' ? 'opacity-0' : ''}`}
            onClick={(e) => { e.stopPropagation(); onToggleExpand(nodeId); }}
          >
            {(hasChildren || node.type !== 'whiteboard') && (
               isExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />
            )}
          </div>

          {/* Icon (Click to Change) */}
          <div 
            className="shrink-0 cursor-pointer hover:scale-110 transition-transform"
            onClick={(e) => toggleEmojiPicker(e, nodeId)}
          >
            {getIcon()}
          </div>

          {/* Name (Double Click to Rename) */}
          {isEditing ? (
            <input 
                ref={editInputRef}
                value={editValue}
                onChange={(e) => setEditValue(e.target.value)}
                onBlur={finishRenaming}
                onKeyDown={handleKeyDown}
                onClick={(e) => e.stopPropagation()}
                className="flex-1 bg-transparent border-none p-0 text-[13px] text-gray-900 outline-none h-5 min-w-0 focus:ring-0 font-inherit"
            />
          ) : (
            <span 
                className="truncate flex-1"
                onDoubleClick={(e) => startRenaming(e, node)}
            >
                {node.name}
            </span>
          )}

          {/* Quick Actions (Hover) */}
          <div className={`flex items-center gap-1 ${activeMenuId === nodeId ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
             {node.type !== 'whiteboard' && (
                <button 
                    onClick={(e) => { e.stopPropagation(); onCreateNode('folder', nodeId); }} 
                    className="w-5 h-5 flex items-center justify-center rounded hover:bg-gray-200 text-gray-400 hover:text-gray-700"
                    title="New Sub-folder"
                >
                    <Plus size={12} />
                </button>
             )}
             <button 
                onClick={(e) => toggleMenu(e, nodeId)}
                className={`w-5 h-5 flex items-center justify-center rounded hover:bg-gray-200 transition-colors ${activeMenuId === nodeId ? 'text-gray-900 bg-gray-200' : 'text-gray-400 hover:text-gray-700'}`}
             >
                <MoreHorizontal size={12} />
             </button>
          </div>
        </div>

        {/* --- EMOJI POPUP --- */}
        {activeEmojiId === nodeId && (
            <div 
                className="absolute left-full top-0 ml-2 bg-white rounded-xl shadow-xl border border-gray-100 p-2 z-50 grid grid-cols-5 gap-1 w-48 animate-in fade-in zoom-in-95 duration-100"
                onClick={(e) => e.stopPropagation()}
            >
                {EMOJI_LIST.map(emoji => (
                    <button 
                        key={emoji} 
                        onClick={() => selectEmoji(nodeId, emoji)}
                        className="w-8 h-8 flex items-center justify-center text-[16px] hover:bg-gray-100 rounded-lg transition-colors"
                    >
                        {emoji}
                    </button>
                ))}
                {/* Reset Option */}
                <button 
                    onClick={() => selectEmoji(nodeId, '')}
                    className="col-span-5 text-[10px] text-gray-400 hover:text-red-500 py-1 font-medium mt-1 border-t border-gray-100"
                >
                    Reset Icon
                </button>
            </div>
        )}

        {/* --- CONTEXT MENU --- */}
        {activeMenuId === nodeId && (
            <div 
                className="absolute right-2 top-8 bg-white rounded-lg shadow-xl border border-gray-100 py-1 w-32 z-50 flex flex-col animate-in fade-in zoom-in-95 duration-100 origin-top-right"
                onClick={(e) => e.stopPropagation()}
            >
                <button 
                    onClick={(e) => startRenaming(e, node)}
                    className="flex items-center gap-2 px-3 py-2 text-[12px] text-gray-700 hover:bg-gray-50 text-left"
                >
                    <Edit2 size={12} /> Rename
                </button>
                <button 
                    onClick={() => { onDeleteNode(nodeId); setActiveMenuId(null); }}
                    className="flex items-center gap-2 px-3 py-2 text-[12px] text-red-600 hover:bg-red-50 text-left"
                >
                    <Trash2 size={12} /> Delete
                </button>
            </div>
        )}

        {/* Render Children */}
        {isExpanded && (
          <div>
            {children.map(child => (
              <TreeItem key={child.id} nodeId={child.id} depth={depth + 1} />
            ))}

            {/* Empty Folder State in Tree */}
            {children.length === 0 && (node.type === 'folder' || node.type === 'page') && (
                 <div className="px-2 mx-2 py-1 text-[12px] text-gray-300 italic select-none" style={{ paddingLeft: `${(depth + 1) * 16 + 28}px` }}>
                    Empty
                 </div>
            )}
          </div>
        )}
      </div>
    );
  };

  return (
    // Updated Background to Sandy Peach with 30% Opacity and matching border
    <div className="w-[280px] h-full bg-[#F9E6D1]/30 border-r border-[#F9E6D1]/60 flex flex-col flex-shrink-0 font-sans">

      {/* --- SEARCH --- */}
      <div className="px-3 pt-4 mb-6">
         <div className="relative group">
            <Search size={14} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" />
            <input 
              className="w-full bg-white border border-gray-200 rounded-lg pl-8 pr-3 py-1.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 focus:border-[#3A5C34] outline-none transition-all placeholder-gray-400"
              placeholder="Search..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
         </div>
      </div>

      {/* --- QUICK LINKS --- */}
      <div className="px-2 mb-6">
          <button 
             onClick={() => onNavigate('root')} 
             className={`w-full flex items-center gap-3 px-3 py-1.5 text-[13px] font-medium rounded-lg transition-colors ${activeNodeId === 'root' ? 'bg-[#3A5C34]/10 text-[#3A5C34]' : 'text-gray-700 hover:bg-[#FCCAE2]/20 hover:text-gray-900'}`}
          >
              <Home size={16} className={activeNodeId === 'root' ? 'text-[#3A5C34]' : 'text-gray-400'} />
              Home
          </button>
          <button 
             onClick={() => onNavigate('recents')}
             className={`w-full flex items-center gap-3 px-3 py-1.5 text-[13px] font-medium rounded-lg transition-colors ${activeNodeId === 'recents' ? 'bg-[#3A5C34]/10 text-[#3A5C34]' : 'text-gray-700 hover:bg-[#FCCAE2]/20 hover:text-gray-900'}`}
          >
              <Clock size={16} className={activeNodeId === 'recents' ? 'text-[#3A5C34]' : 'text-gray-400'} />
              Recents
          </button>
          <button 
             onClick={() => onNavigate('favorites')}
             className={`w-full flex items-center gap-3 px-3 py-1.5 text-[13px] font-medium rounded-lg transition-colors ${activeNodeId === 'favorites' ? 'bg-[#3A5C34]/10 text-[#3A5C34]' : 'text-gray-700 hover:bg-[#FCCAE2]/20 hover:text-gray-900'}`}
          >
              <Star size={16} className={activeNodeId === 'favorites' ? 'text-[#FFD753] fill-[#FFD753]' : 'text-gray-400'} />
              Favorites
          </button>
      </div>

      {/* --- FOLDER TREE --- */}
      <div className="flex-1 overflow-y-auto no-scrollbar pb-4">

         <div className="px-4 mb-2 flex items-center justify-between">
             <span className="text-[11px] font-bold text-gray-400 uppercase tracking-wider">Folders</span>
             <button 
                onClick={() => onCreateNode('folder', null)}
                className="p-1 rounded hover:bg-gray-200 text-gray-400 hover:text-gray-600 transition-colors"
             >
                 <Plus size={12} />
             </button>
         </div>

         <div className="space-y-0.5">
            {getRootNodes().map(node => (
                <TreeItem key={node.id} nodeId={node.id} />
            ))}
         </div>

         {getRootNodes().length === 0 && (
             <div className="px-4 py-4 text-center text-[12px] text-gray-400">
                 No folders yet
             </div>
         )}
      </div>

      {/* --- WORKSPACE SWITCHER --- */}
      <div className="relative p-3 flex gap-2">
         {showProfileMenu && (
             <div className="absolute bottom-full left-3 right-3 mb-2 bg-white rounded-xl shadow-xl border border-gray-100 p-1 z-50 animate-in slide-in-from-bottom-2 fade-in">
                 <button 
                    onClick={handleSignOut}
                    className="w-full flex items-center gap-2 px-3 py-2 text-[13px] text-red-600 hover:bg-red-50 rounded-lg transition-colors text-left font-medium"
                 >
                     <LogOut size={14} /> Sign Out
                 </button>
             </div>
         )}

         <button 
            onClick={(e) => { e.stopPropagation(); setShowProfileMenu(!showProfileMenu); }}
            className="flex-1 flex items-center gap-3 p-2 rounded-xl hover:bg-white hover:shadow-sm hover:border-gray-100 border border-transparent transition-all group"
         >
             <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-[#3A5C34] to-[#2d4a29] text-white flex items-center justify-center text-[12px] font-bold shadow-sm overflow-hidden">
                 {avatarUrl ? (
                     <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                 ) : (
                     <span>{initials}</span>
                 )}
             </div>
             <div className="flex-1 text-left min-w-0">
                 <div className="text-[13px] font-semibold text-gray-900 leading-none truncate">{displayName}</div>
                 <div className="text-[11px] text-gray-500 mt-0.5 truncate">{displaySubtitle}</div>
             </div>
             <ChevronDown size={14} className="text-gray-400 group-hover:text-gray-600 shrink-0" />
         </button>

         {/* Sound Toggle */}
         <button 
            onClick={handleToggleSound}
            className={`w-9 flex items-center justify-center transition-all ${isMuted ? 'text-gray-400 hover:text-gray-600' : 'text-[#3A5C34] hover:text-[#2d4a29]'}`}
            title={isMuted ? "Unmute Sounds" : "Mute Sounds"}
         >
             {isMuted ? <VolumeX size={16} /> : <Volume2 size={16} />}
         </button>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { FileSystemNode } from '../types';
import { OrbitLogo } from './ui/OrbitLogo';
import { 
  Clock, 
  Star, 
  Plus, 
  Folder, 
  Search, 
  Grid2X2, 
  List as ListIcon, 
  LayoutTemplate,
  MoreHorizontal,
  X,
  Compass
} from 'lucide-react';

interface PageViewProps {
  node: FileSystemNode;
  childNodes: FileSystemNode[];
  onNavigate: (id: string) => void;
  onCreateWhiteboard: () => void;
  onCreateFolder: () => void;
  onToggleFavorite?: (id: string) => void;
  onUpdateNode: (id: string, updates: Partial<FileSystemNode>) => void;
  onReorderNode?: (dragId: string, targetId: string) => void;
  tourCompleted?: boolean;
  onDismissTour?: () => void;
}

// --- COLOR UTILS ---
// Deterministically assign a brand color theme based on the ID string
const getBrandTheme = (id: string) => {
  const themes = [
    // Yellow Theme
    { 
      bg: 'bg-[#FFD753]/20', 
      text: 'text-[#b89514]', 
      border: 'hover:border-[#FFD753]', 
      icon: '#d9b01c',
      shadow: 'hover:shadow-[#FFD753]/20'
    },
    // Green Theme
    { 
      bg: 'bg-[#3A5C34]/10', 
      text: 'text-[#3A5C34]', 
      border: 'hover:border-[#3A5C34]', 
      icon: '#3A5C34',
      shadow: 'hover:shadow-[#3A5C34]/20'
    },
    // Pink Theme
    { 
      bg: 'bg-[#FCCAE2]/40', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#FCCAE2]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#FCCAE2]/40'
    },
    // Burgundy Theme
    { 
      bg: 'bg-[#5F2427]/10', 
      text: 'text-[#5F2427]', 
      border: 'hover:border-[#5F2427]', 
      icon: '#5F2427',
      shadow: 'hover:shadow-[#5F2427]/20'
    },
  ];

  const index = id.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0) % themes.length;
  return themes[index];
};

export const PageView: React.FC<PageViewProps> = ({
  node,
  childNodes,
  onNavigate,
  onCreateWhiteboard,
  onCreateFolder,
  onToggleFavorite,
  onUpdateNode,
  onReorderNode,
  tourCompleted,
  onDismissTour
}) => {
  const [searchQuery, setSearchQuery] = useState("");
  const [draggedItemId, setDraggedItemId] = useState<string | null>(null);

  // Renaming State (Grid Items)
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editName, setEditName] = useState("");

  // Renaming State (Header)
  const [isRenamingHeader, setIsRenamingHeader] = useState(false);
  const [headerName, setHeaderName] = useState("");

  const whiteboards = childNodes.filter(n => n.type === 'whiteboard');
  const folders = childNodes.filter(n => n.type !== 'whiteboard');

  const filteredWhiteboards = whiteboards.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));
  const filteredFolders = folders.filter(n => n.name.toLowerCase().includes(searchQuery.toLowerCase()));

  // Don't show "Create" buttons in special views like Recents/Favorites unless appropriate
  const isSpecialView = ['recents', 'favorites'].includes(node.id);
  const isRoot = node.id === 'root';

  // --- Grid Renaming Handlers ---
  const handleStartRenaming = (e: React.MouseEvent, item: FileSystemNode) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingId(item.id);
    setEditName(item.name);
  };

  const handleSaveRenaming = () => {
    if (editingId && editName.trim()) {
      onUpdateNode(editingId, { name: editName.trim() });
    }
    setEditingId(null);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveRenaming();
    if (e.key === 'Escape') setEditingId(null);
  };

  // --- Header Renaming Handlers ---
  const handleStartHeaderRenaming = () => {
    if (isSpecialView) return;
    setIsRenamingHeader(true);
    setHeaderName(node.name);
  };

  const handleSaveHeaderRenaming = () => {
    if (headerName.trim()) {
      onUpdateNode(node.id, { name: headerName.trim() });
    }
    setIsRenamingHeader(false);
  };

  const handleHeaderKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSaveHeaderRenaming();
    if (e.key === 'Escape') setIsRenamingHeader(false);
  };

  // --- Drag and Drop Handlers ---
  const handleDragStart = (e: React.DragEvent, id: string) => {
      if (editingId || isRenamingHeader) {
          e.preventDefault();
          return;
      }
      setDraggedItemId(id);
      e.dataTransfer.setData('nodeId', id);
      e.dataTransfer.effectAllowed = 'move';
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '0.5';
      }
  };

  const handleDragEnd = (e: React.DragEvent) => {
      setDraggedItemId(null);
      if (e.target instanceof HTMLElement) {
          e.target.style.opacity = '1';
      }
  };

  const handleDragOver = (e: React.DragEvent) => {
      e.preventDefault(); 
      e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e: React.DragEvent, targetId: string) => {
      e.preventDefault();
      const dragId = e.dataTransfer.getData('nodeId');
      if (dragId && dragId !== targetId && onReorderNode) {
          onReorderNode(dragId, targetId);
      }
      setDraggedItemId(null);
  };

  return (
    <div className="flex-1 bg-white h-full overflow-y-auto no-scrollbar font-sans selection:bg-[#FCCAE2] selection:text-[#5F2427]">
      <div className="max-w-[1400px] mx-auto p-8 lg:p-12">

        {/* --- TOUR CARD --- */}
        {isRoot && !tourCompleted && onDismissTour && (
            <div className="mb-10 bg-[#3A5C34] text-white rounded-[24px] p-6 shadow-xl relative animate-in slide-in-from-top-4 fade-in duration-500 overflow-hidden">
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/4 pointer-events-none"></div>

                <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div className="space-y-3 max-w-2xl">
                        <div className="flex items-center gap-2 text-[#FFD753] font-bold text-[11px] uppercase tracking-wider">
                            <Compass size={14} /> Getting Started
                        </div>
                        <h2 className="text-[24px] font-bold tracking-tight">Welcome to your workspace</h2>
                        <p className="text-[15px] text-white/80 leading-relaxed">
                            We've set up a few starter folders for you below. 
                            You can rename, move, or delete them anytime. 
                            Create new <strong>Folders</strong> to organize, and <strong>Whiteboards</strong> to visualize your ideas.
                        </p>
                    </div>
                    <button 
                        onClick={onDismissTour}
                        className="bg-white text-[#3A5C34] px-6 py-3 rounded-full font-semibold text-[14px] shadow-sm hover:bg-[#F2F2F7] transition-all active:scale-95 whitespace-nowrap self-start md:self-center"
                    >
                        Got it, thanks
                    </button>
                </div>

                <button 
                    onClick={onDismissTour}
                    className="absolute top-4 right-4 p-2 text-white/50 hover:text-white transition-colors"
                >
                    <X size={20} />
                </button>
            </div>
        )}

        {/* --- HEADER --- */}
        <header className="flex flex-col gap-6 mb-10">

          {/* Top Row: Breadcrumbs / Title + Logo */}
          <div className="flex justify-between items-end">
             <div className="flex flex-col gap-2">
                 <div className="flex items-center gap-2 text-[13px] font-medium text-gray-400">
                    <span>Workspace</span>
                    <span className="text-[#FFD753]">/</span>
                    <span className="text-[#3A5C34]">{node.name}</span>
                 </div>

                 <div className="flex items-center gap-3 h-[48px]">
                    {node.icon && <span className="text-[32px]">{node.icon}</span>}

                    {isRenamingHeader ? (
                        <input
                            value={headerName}
                            onChange={(e) => setHeaderName(e.target.value)}
                            onBlur={handleSaveHeaderRenaming}
                            onKeyDown={handleHeaderKeyDown}
                            autoFocus
                            className="text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight bg-transparent border-none outline-none w-full max-w-lg p-0 placeholder-[#5F2427]/30 focus:ring-0"
                        />
                    ) : (
                        // Using Deep Burgundy for the Header to give it weight and warmth
                        <h1 
                            className={`text-[32px] font-bold text-[#5F2427] tracking-tight leading-tight ${!isSpecialView ? 'cursor-text hover:text-[#3A5C34] transition-colors' : ''}`}
                            onDoubleClick={handleStartHeaderRenaming}
                        >
                            {node.name}
                        </h1>
                    )}
                 </div>
             </div>

             {/* Orbit Logo in Top Right Corner - Resized to 40px and aligned to Title baseline */}
             <OrbitLogo className="w-10 h-10 text-[#5F2427] mb-1" />
          </div>

          {/* Controls Row: Search & Actions */}
          <div className="flex items-center justify-between gap-4">
             {/* Search */}
             <div className="relative flex-1 max-w-sm group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-[#3A5C34] transition-colors" size={16} />
                <input 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full h-10 bg-gray-50/50 border border-gray-200 rounded-xl pl-9 pr-4 text-[14px] text-gray-900 placeholder-gray-400 focus:ring-2 focus:ring-[#FCCAE2] focus:border-[#5F2427] transition-all outline-none"
                  placeholder="Filter items..."
                />
             </div>

             {/* Actions */}
             <div className="flex items-center gap-3">
                <div className="flex items-center bg-gray-50 p-0.5 rounded-xl border border-gray-200 mr-2">
                    <button className="p-1.5 bg-white rounded-lg shadow-sm text-[#3A5C34]"><Grid2X2 size={16}/></button>
                    <button className="p-1.5 text-gray-400 hover:text-[#5F2427]"><ListIcon size={16}/></button>
                </div>

                {!isSpecialView && (
                  <>
                    <button 
                      onClick={onCreateFolder}
                      className="h-9 px-4 rounded-xl bg-white border border-gray-200 text-[#3A5C34] font-medium text-[13px] hover:bg-gray-50 hover:border-[#3A5C34]/30 transition-all active:scale-95 flex items-center gap-2 shadow-sm"
                    >
                      <Folder size={14} className="text-[#FFD753] fill-[#FFD753]" />
                      New Folder
                    </button>

                    <button 
                      onClick={onCreateWhiteboard}
                      // New Chic Combo: Burgundy BG + Pink Text
                      className="h-9 px-4 rounded-xl bg-[#5F2427] text-[#FCCAE2] font-medium text-[13px] hover:bg-[#4a1c1e] transition-all active:scale-95 flex items-center gap-2 shadow-md shadow-[#5F2427]/20"
                    >
                      <Plus size={14} />
                      New Whiteboard
                    </button>
                  </>
                )}
             </div>
          </div>
        </header>

        {/* --- SECTIONS --- */}

        {/* 1. FOLDERS */}
        {(filteredFolders.length > 0 || (!searchQuery && !isSpecialView)) && (
            <section className="mb-12">
                <div className="flex items-center gap-2 mb-4">
                    <h2 className="text-[14px] font-semibold text-[#5F2427]">Folders</h2>
                    <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredFolders.length}</span>
                </div>

                {filteredFolders.length > 0 ? (
                    <div className="grid grid-cols-1 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
                        {filteredFolders.map(folder => {
                            const theme = getBrandTheme(folder.id);
                            const isEditing = editingId === folder.id;

                            // Check for sub-items count
                            const subItemCount = childNodes.filter(c => c.parentId === folder.id).length; // NOTE: This actually needs recursive check in real app, here it checks siblings which is wrong for tree. 
                            // Correct logic requires checking global store or just showing placeholder. 
                            // Since we don't have global nodes here, we just show "0 items" or omit count logic for simplicity in this view component.

                            return (
                                <div 
                                    key={folder.id}
                                    onClick={() => !isEditing && onNavigate(folder.id)}
                                    draggable
                                    onDragStart={(e) => handleDragStart(e, folder.id)}
                                    onDragEnd={handleDragEnd}
                                    onDragOver={handleDragOver}
                                    onDrop={(e) => handleDrop(e, folder.id)}
                                    className={`
                                        group flex flex-col gap-3 p-4 rounded-2xl border bg-white transition-all text-left relative h-full cursor-pointer
                                        ${draggedItemId === folder.id 
                                            ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                            : `border-gray-100 ${theme.border} hover:shadow-lg ${theme.shadow}`
                                        }
                                    `}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform ${folder.icon ? 'bg-gray-50' : theme.bg}`}>
                                            {folder.icon ? (
                                                <span className="text-[20px]">{folder.icon}</span>
                                            ) : (
                                                <Folder size={18} fill="currentColor" className={theme.text} />
                                            )}
                                        </div>
                                        <div className="min-w-0 flex-1">
                                            {isEditing ? (
                                                <input
                                                    value={editName}
                                                    onChange={(e) => setEditName(e.target.value)}
                                                    onBlur={handleSaveRenaming}
                                                    onKeyDown={handleKeyDown}
                                                    autoFocus
                                                    onClick={(e) => e.stopPropagation()}
                                                    className="w-full text-[14px] font-bold text-[#1C1C1E] bg-transparent border-none p-0 outline-none focus:ring-0"
                                                />
                                            ) : (
                                                <h3 
                                                    className={`text-[14px] font-bold text-gray-900 truncate group-hover:${theme.text} transition-colors select-none`}
                                                    onDoubleClick={(e) => handleStartRenaming(e, folder)}
                                                >
                                                    {folder.name}
                                                </h3>
                                            )}
                                        </div>
                                    </div>

                                    {folder.description && (
                                        <p className="text-[12px] text-gray-500 leading-relaxed line-clamp-2 min-h-[32px]">
                                            {folder.description}
                                        </p>
                                    )}

                                    <div className="mt-auto pt-2 text-[11px] text-gray-400 font-medium flex items-center gap-1">
                                        <div className={`w-1.5 h-1.5 rounded-full ${theme.bg.replace('/20','').replace('/10','').replace('/40','')} opacity-50`}></div>
                                        <span>Folder</span>
                                    </div>

                                    {onToggleFavorite && (
                                      <div 
                                        className="absolute top-2 right-2 p-1.5 rounded-full hover:bg-gray-100 text-gray-300 hover:text-[#FFD753] transition-all opacity-0 group-hover:opacity-100"
                                        onClick={(e) => { e.stopPropagation(); onToggleFavorite(folder.id); }}
                                      >
                                        <Star size={14} fill={folder.isFavorite ? "currentColor" : "none"} className={folder.isFavorite ? "text-[#FFD753]" : ""} />
                                      </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="text-gray-400 text-[13px] italic py-8 border border-dashed border-gray-200 rounded-2xl flex flex-col items-center justify-center bg-[#f9fafb]">
                        <Folder size={24} className="mb-2 opacity-20 text-[#3A5C34]" />
                        {searchQuery ? "No folders found" : "Empty workspace"}
                    </div>
                )}
            </section>
        )}

        {/* 2. WHITEBOARDS */}
        <section>
            <div className="flex items-center gap-2 mb-4">
                <h2 className="text-[14px] font-semibold text-[#5F2427]">Whiteboards</h2>
                <span className="px-1.5 py-0.5 rounded-md bg-[#FCCAE2]/30 text-[11px] font-bold text-[#5F2427]">{filteredWhiteboards.length}</span>
            </div>

            {filteredWhiteboards.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6">
                    {/* Create New Card (Inline) - Only show if allowed */}
                    {!isSpecialView && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Grid Button: Burgundy Border + Text on hover
                            className="group flex flex-col items-center justify-center gap-3 bg-white rounded-2xl border-2 border-dashed border-gray-200 hover:border-[#5F2427] hover:bg-[#FCCAE2]/10 transition-all cursor-pointer aspect-[4/3]"
                        >
                            <div className="w-12 h-12 rounded-full bg-white shadow-sm border border-gray-100 flex items-center justify-center text-gray-400 group-hover:text-[#5F2427] group-hover:scale-110 transition-all duration-300">
                                <Plus size={20} />
                            </div>
                            <span className="text-[13px] font-bold text-gray-400 group-hover:text-[#5F2427]">Create New</span>
                        </button>
                    )}

                    {filteredWhiteboards.map(wb => (
                        <div 
                          key={wb.id}
                          onClick={() => editingId !== wb.id && onNavigate(wb.id)}
                          draggable
                          onDragStart={(e) => handleDragStart(e, wb.id)}
                          onDragEnd={handleDragEnd}
                          onDragOver={handleDragOver}
                          onDrop={(e) => handleDrop(e, wb.id)}
                          className={`
                              group relative flex flex-col bg-white rounded-3xl border overflow-hidden transition-all duration-300 cursor-pointer
                              ${draggedItemId === wb.id 
                                  ? 'opacity-40 border-dashed border-[#3A5C34]' 
                                  : 'border-gray-100 hover:border-[#FCCAE2] hover:shadow-xl hover:shadow-[#5F2427]/5'
                              }
                          `}
                        >
                            {/* Preview Area - Light & Clean */}
                            <div className="aspect-[4/3] bg-[#f9fafb] relative overflow-hidden border-b border-gray-50">
                                {/* Dot Pattern Background */}
                                <div className="absolute inset-0 opacity-[0.3]" 
                                     style={{ backgroundImage: 'radial-gradient(#94a3b8 1px, transparent 1px)', backgroundSize: '16px 16px' }}>
                                </div>

                                {/* Abstract Content Hint (Using Brand Colors) */}
                                <div className="absolute inset-6 bg-white rounded-xl shadow-[0_4px_20px_-4px_rgba(0,0,0,0.1)] border border-gray-100 group-hover:scale-105 group-hover:-translate-y-1 transition-transform duration-500 flex flex-col p-3 gap-2">
                                    <div className="w-1/3 h-2 bg-gray-100 rounded-full"></div>
                                    <div className="flex gap-2">
                                        <div className="w-8 h-8 rounded-lg bg-[#3A5C34]/20 border border-[#3A5C34]/10"></div>
                                        <div className="w-8 h-8 rounded-lg bg-[#FCCAE2]/40 border border-[#FCCAE2]/20"></div>
                                        <div className="w-12 h-8 rounded-lg bg-[#FFD753]/20 border border-[#FFD753]/10 ml-auto"></div>
                                    </div>
                                    <div className="mt-auto w-1/2 h-2 bg-[#5F2427]/10 rounded-full"></div>
                                </div>

                                {/* Hover Overlay Button - Chic Burgundy & Yellow */}
                                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-white/40 backdrop-blur-[2px]">
                                    <div className="px-5 py-2 bg-[#5F2427] shadow-lg rounded-full text-[12px] font-bold text-[#FFD753] tracking-wide transform translate-y-2 group-hover:translate-y-0 transition-transform">
                                        Open Board
                                    </div>
                                </div>
                            </div>

                            {/* Info Footer */}
                            <div className="p-4 flex flex-col gap-1">
                                <div className="flex items-center justify-between gap-2">
                                    <div className="min-w-0 flex-1">
                                        {editingId === wb.id ? (
                                            <input
                                                value={editName}
                                                onChange={(e) => setEditName(e.target.value)}
                                                onBlur={handleSaveRenaming}
                                                onKeyDown={handleKeyDown}
                                                autoFocus
                                                onClick={(e) => e.stopPropagation()}
                                                className="w-full text-[14px] font-bold text-[#1C1C1E] bg-transparent border-none p-0 outline-none focus:ring-0"
                                            />
                                        ) : (
                                            <h3 
                                                className="text-[14px] font-bold text-[#1C1C1E] truncate flex items-center gap-2 select-none group-hover:text-[#5F2427] transition-colors"
                                                onDoubleClick={(e) => handleStartRenaming(e, wb)}
                                            >
                                                {wb.icon && <span>{wb.icon}</span>}
                                                {wb.name}
                                            </h3>
                                        )}
                                    </div>

                                    {onToggleFavorite && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); onToggleFavorite(wb.id); }}
                                            className={`hover:text-[#FFD753] transition-opacity shrink-0 ${wb.isFavorite ? 'text-[#FFD753] opacity-100' : 'text-gray-300 opacity-0 group-hover:opacity-100'}`}
                                        >
                                            <Star size={14} fill={wb.isFavorite ? "currentColor" : "none"} />
                                        </button>
                                    )}
                                </div>
                                <div className="flex items-center justify-between mt-1">
                                    <span className="text-[11px] text-gray-400 flex items-center gap-1 font-medium">
                                        <Clock size={10} /> {wb.lastEdited || 'Just now'}
                                    </span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-20 text-center border-2 border-dashed border-gray-200 rounded-3xl bg-[#f9fafb]">
                    <div className="w-16 h-16 bg-white rounded-2xl shadow-sm border border-gray-100 flex items-center justify-center mb-4">
                        <LayoutTemplate size={28} className="text-[#3A5C34] opacity-50" />
                    </div>
                    <p className="text-[15px] font-bold text-gray-900">No whiteboards created yet</p>
                    <p className="text-[13px] text-gray-500 mb-6 max-w-xs leading-relaxed">
                        {searchQuery ? "Try adjusting your search terms." : "Start your first project in this folder to begin visualizing your strategy."}
                    </p>
                    {!isSpecialView && !searchQuery && (
                        <button 
                            onClick={onCreateWhiteboard}
                            // Empty State Button: Burgundy BG + Pink Text
                            className="px-6 py-2.5 rounded-full bg-[#5F2427] text-[#FCCAE2] font-semibold text-[13px] shadow-lg hover:bg-[#4a1c1e] transition-all hover:scale-105 active:scale-95"
                        >
                            Create Whiteboard
                        </button>
                    )}
                </div>
            )}
        </section>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud } from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// Helper to ensure text readability on light colors
const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427'; // Default Burgundy
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color }; // Yellow -> Dark Gold Text
        case '#FCCAE2': return { text: '#9D174D', bg: color }; // Pink -> Dark Pink Text
        case '#FF9500': return { text: '#C2410C', bg: color }; // Orange -> Dark Orange Text
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);

  // --- User Identity State ---
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State (Active Board) ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  // --- Canvas Tools & State ---
  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  // --- UI State ---
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false); // Tool drawer
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);

  // Tab Editing State
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");

  // Whiteboard Title Renaming State
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  // Undo/Redo Stacks (Per Whiteboard Session)
  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);

    setUserProfile(profile);
    setBrand(userBrand);

    if (profile) {
      setOnboardingComplete(profile.onboarding_complete);
    }
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        // --- INITIALIZE DEFAULT STRUCTURE ---
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  // Save on change (Debounced)
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => {
        setIsSyncing(false);
      });
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- TOUR DISMISSAL ---
  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          // Optimistically update local state
          if (userProfile) {
              setUserProfile({ ...userProfile, tour_completed: true });
          }
      } catch (e) {
          console.error("Failed to dismiss tour", e);
      }
  };

  // --- DERIVED STATE ---
  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  // Resolve what to show in PageView
  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];

  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder'); // Mock recents
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  // --- HANDLERS (Same as before) ---
  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: {
                ...prev[activeNodeId],
                whiteboardData: workspaces
            }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const handleToggleExpand = (id: string) => {
    setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }));
  };

  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    soundService.play('success');
    const newId = `${type}-${Date.now()}`;
    const effectiveParentId = (isSpecialView || !nodes[activeNodeId]) ? null : activeNodeId;
    const siblings = (Object.values(nodes) as FileSystemNode[]).filter(n => n.parentId === effectiveParentId);
    const maxOrder = siblings.length > 0 ? Math.max(...siblings.map(n => n.order || 0)) : -1;

    const newNode: FileSystemNode = {
        id: newId,
        type,
        name: `New ${type.charAt(0).toUpperCase() + type.slice(1)}`,
        parentId: parentId || effectiveParentId,
        isExpanded: true,
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined,
        lastEdited: 'Just now',
        order: maxOrder + 1
    };

    setNodes(prev => {
        const parentUpdates = (parentId && prev[parentId]) ? { [parentId]: { ...prev[parentId], isExpanded: true } } : {};
        return { ...prev, ...parentUpdates, [newId]: newNode };
    });

    if (type !== 'folder') handleNavigate(newId);
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
    setNodes(prev => ({ ...prev, [id]: { ...prev[id], ...updates } }));
  };

  const handleToggleFavorite = (id: string) => {
    soundService.play('toggle');
    setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const newNodes = { ...prev };
          const deleteRecursively = (nodeId: string) => {
              (Object.values(newNodes) as FileSystemNode[]).filter(n => n.parentId === nodeId).forEach(child => deleteRecursively(child.id));
              delete newNodes[nodeId];
          };
          deleteRecursively(id);
          return newNodes;
      });
      if (activeNodeId === id || !nodes[activeNodeId]) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
     setNodes(prev => ({ ...prev, [dragId]: { ...prev[dragId], parentId: targetId } }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
    const dragNode = nodes[dragId];
    const targetNode = nodes[targetId];
    if (!dragNode || !targetNode || dragNode.parentId !== targetNode.parentId) return;
    const siblings = (Object.values(nodes) as FileSystemNode[])
        .filter(n => n.parentId === dragNode.parentId && n.type === dragNode.type)
        .sort((a, b) => (a.order || 0) - (b.order || 0));

    const dragIndex = siblings.findIndex(n => n.id === dragId);
    const targetIndex = siblings.findIndex(n => n.id === targetId);
    if (dragIndex === -1 || targetIndex === -1 || dragIndex === targetIndex) return;

    const newSiblings = [...siblings];
    newSiblings.splice(dragIndex, 1);
    newSiblings.splice(targetIndex, 0, dragNode);

    const updates: Record<string, Partial<FileSystemNode>> = {};
    newSiblings.forEach((node, index) => {
        if ((node.order || 0) !== index) updates[node.id] = { order: index };
    });

    if (Object.keys(updates).length > 0) {
        setNodes(prev => {
            const next = { ...prev };
            Object.entries(updates).forEach(([id, update]) => { next[id] = { ...next[id], ...update }; });
            return next;
        });
        soundService.play('snap');
    }
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId && nodes[realNode.parentId]) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  // --- Title Renaming ---
  const startTitleRename = (e: React.MouseEvent) => {
    if (!realNode) return;
    e.stopPropagation();
    setIsRenamingTitle(true);
    setTitleInputValue(displayedNode.name);
  };

  const saveTitleRename = () => {
    if (titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() });
    setIsRenamingTitle(false);
  };

  const handleTitleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') saveTitleRename();
    if (e.key === 'Escape') setIsRenamingTitle(false);
  };

  // --- Whiteboard Logic ---
  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(prev => prev.slice(0, -1));
    updateCardsNoHistory(previous);
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(prev => prev.slice(1));
    updateCardsNoHistory(next);
  };

  const updateCardsNoHistory = (newCards: CardData[]) => {
      const updated = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  // Global keys
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
          if (e.key.toLowerCase() === 't') setActiveTool('TEXT');
          if (e.key.toLowerCase() === 'n') setActiveTool('STICKY');
          if (e.key.toLowerCase() === 'p') setActiveTool('PEN');
          if ((e.metaKey || e.ctrlKey) && e.key === 'z') { e.preventDefault(); handleUndo(); }
          if ((e.metaKey || e.ctrlKey) && e.key === 'y') { e.preventDefault(); handleRedo(); }
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, history, future, activeWorkspaceId, isWhiteboardMode]);

  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = {
      id: `tab-${Date.now()}`,
      name: `Sheet ${workspaces.length + 1}`,
      cards: [],
      color: TAB_COLORS[workspaces.length % TAB_COLORS.length]
    };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) setColorPickerState(null);
    else {
      const rect = e.currentTarget.getBoundingClientRect();
      setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const startTabRename = (e: React.MouseEvent, ws: Workspace) => {
    e.stopPropagation();
    e.preventDefault();
    setEditingTabId(ws.id);
    setEditTabName(ws.name);
    setColorPickerState(null);
  };

  const finishTabRename = () => {
    if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim());
    setEditingTabId(null);
  };

  const handleTabKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') finishTabRename();
    if (e.key === 'Escape') setEditingTabId(null);
  };

  // --- RENDER CONDITIONAL VIEWS ---

  if (authLoading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]">
