/**
 * Persistence Strategy:
 * We store the entire FileSystemNode tree in a single JSONB column per user.
 * Table: 'user_files'
 * Columns: 'user_id' (uuid, primary key), 'data' (jsonb)
 */

// --- DATA PERSISTENCE ---

export const saveNodesToSupabase = async (nodes: Record<string, FileSystemNode>) => {
  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return;

    const { error } = await supabase
      .from('user_files')
      .upsert({ 
        user_id: session.user.id, 
        data: nodes,
        updated_at: new Date().toISOString()
      });

    if (error) {
      console.warn('Supabase Save Error:', error.message);
    }
  } catch (e) {
    console.error('Unexpected Supabase Error:', e);
  }
};

export const loadNodesFromSupabase = async (): Promise<Record<string, FileSystemNode> | null> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return null;

    const { data, error } = await supabase
      .from('user_files')
      .select('data')
      .eq('user_id', session.user.id)
      .single();

    if (error) {
      // PGRST116 means row not found (user has no data yet)
      if (error.code !== 'PGRST116') {
        console.log('Supabase Load Status:', error.message);
      }
      return null;
    }
    return data?.data as Record<string, FileSystemNode>;
  } catch (e) {
    console.error('Unexpected Supabase Load Error:', e);
    return null;
  }
};

// --- AUTH & PROFILE ---

export const getUserProfile = async (userId: string): Promise<UserProfile | null> => {
  const { data, error } = await supabase
    .from('profiles')
    .select('*')
    .eq('id', userId)
    .single();

  if (error) {
    console.warn('Error fetching profile:', error.message);
    return null;
  }
  return data as UserProfile;
};

export const getUserBrand = async (userId: string): Promise<Brand | null> => {
  const { data, error } = await supabase
    .from('brands')
    .select('*')
    .eq('owner_id', userId)
    .single();

  if (error) {
    return null;
  }
  return data as Brand;
};

export const updateUserProfile = async (userId: string, updates: Partial<UserProfile>) => {
  const { error } = await supabase
    .from('profiles')
    .upsert({ id: userId, ...updates, updated_at: new Date().toISOString() });

  if (error) throw error;
};

export const createBrand = async (brandData: Partial<Brand>) => {
  const { error } = await supabase
    .from('brands')
    .insert([brandData]);

  if (error) throw error;
};

export const signOut = async () => {
  await supabase.auth.signOut();
};

