// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS ---
