                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, color, onClick }: { icon: any, label: string, subLabel: string, color: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm text-white shrink-0`} style={{ backgroundColor: color }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-white rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-gray-100 text-[#5F2427] flex items-center justify-center hover:scale-105 hover:bg-gray-50 active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md border-b border-gray-100 flex flex-col gap-3">
                             <div className="flex items-center justify-between">
                                 <h2 className="text-[20px] font-bold text-[#5F2427] tracking-tight">Toolkit</h2>
                                 <span className="text-[11px] font-bold text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">{searchTerm ? 'Searching' : 'Library'}</span>
                             </div>
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Restored High Fidelity List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20">

                            {/* Essentials */}
                            <div className="animate-in slide-in-from-left-4 duration-300">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Essentials</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={ImageIcon} label="Post Card" subLabel="Social content & assets" color="#3A5C34" onClick={() => addCard(CardType.POST)} />
                                    <ToolButton icon={Type} label="Typography" subLabel="Headings & notes" color="#1C1C1E" onClick={() => setActiveTool('TEXT')} />
                                    <ToolButton icon={StickyNote} label="Sticky Note" subLabel="Quick thoughts" color="#FFD753" onClick={() => setActiveTool('STICKY')} />
                                    <ToolButton icon={Mail} label="Newsletter" subLabel="Email campaigns" color="#5F2427" onClick={() => addCard(CardType.NEWSLETTER)} />
                                </div>
                            </div>

                            {/* Strategy */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-75">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Strategy</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Sparkles} label="Oracle AI" subLabel="Generate hooks & ideas" color="#8B5CF6" onClick={() => addCard(CardType.STRATEGY_AI)} />
                                    <ToolButton icon={BarChart2} label="Analytics" subLabel="KPI tracking" color="#007AFF" onClick={() => addCard(CardType.ANALYTICS)} />
                                    <ToolButton icon={CalendarRange} label="Timeline" subLabel="Gantt chart" color="#FF9500" onClick={() => addCard(CardType.GANTT)} />
                                    <ToolButton icon={Beaker} label="The Lab" subLabel="A/B Testing" color="#D946EF" onClick={() => addCard(CardType.ADS_TEST)} />
                                </div>
                            </div>

                            {/* Production */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-100">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Production</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Film} label="Storyboard" subLabel="Visual sequencing" color="#10B981" onClick={() => addCard(CardType.FILMSTRIP)} />
                                    <ToolButton icon={FileText} label="Script" subLabel="A/V dual column" color="#6B7280" onClick={() => addCard(CardType.AV_SCRIPT)} />
                                    <ToolButton icon={ClipboardList} label="Call Sheet" subLabel="Shoot logistics" color="#F59E0B" onClick={() => addCard(CardType.CALL_SHEET)} />
                                    <ToolButton icon={Users} label="Casting" subLabel="Talent management" color="#EC4899" onClick={() => addCard(CardType.CASTING_BOARD)} />
                                    <ToolButton icon={Package} label="Props" subLabel="Inventory list" color="#6366F1" onClick={() => addCard(CardType.PROP_TABLE)} />
                                </div>
                            </div>

                            {/* Connectors */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-150">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Connectors</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={LayoutGrid} label="Grid Planner" subLabel="Instagram layout" color="#0EA5E9" onClick={() => addCard(CardType.GRID_PLANNER)} />
                                    <ToolButton icon={LinkIcon} label="Pinterest" subLabel="Board integration" color="#E60023" onClick={() => addCard(CardType.PINTEREST)} />
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, color, onClick }: { icon: any, label: string, subLabel: string, color: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm text-white shrink-0`} style={{ backgroundColor: color }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-white rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-gray-100 text-[#5F2427] flex items-center justify-center hover:scale-105 hover:bg-gray-50 active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md border-b border-gray-100 flex flex-col gap-3">
                             <div className="flex items-center justify-between">
                                 <h2 className="text-[20px] font-bold text-[#5F2427] tracking-tight">Toolkit</h2>
                                 <span className="text-[11px] font-bold text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">{searchTerm ? 'Searching' : 'Library'}</span>
                             </div>
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Restored High Fidelity List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20">

                            {/* Essentials */}
                            <div className="animate-in slide-in-from-left-4 duration-300">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Essentials</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={ImageIcon} label="Post Card" subLabel="Social content & assets" color="#3A5C34" onClick={() => addCard(CardType.POST)} />
                                    <ToolButton icon={Type} label="Typography" subLabel="Headings & notes" color="#1C1C1E" onClick={() => setActiveTool('TEXT')} />
                                    <ToolButton icon={StickyNote} label="Sticky Note" subLabel="Quick thoughts" color="#FFD753" onClick={() => setActiveTool('STICKY')} />
                                    <ToolButton icon={Mail} label="Newsletter" subLabel="Email campaigns" color="#5F2427" onClick={() => addCard(CardType.NEWSLETTER)} />
                                </div>
                            </div>

                            {/* Strategy */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-75">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Strategy</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Sparkles} label="Oracle AI" subLabel="Generate hooks & ideas" color="#8B5CF6" onClick={() => addCard(CardType.STRATEGY_AI)} />
                                    <ToolButton icon={BarChart2} label="Analytics" subLabel="KPI tracking" color="#007AFF" onClick={() => addCard(CardType.ANALYTICS)} />
                                    <ToolButton icon={CalendarRange} label="Timeline" subLabel="Gantt chart" color="#FF9500" onClick={() => addCard(CardType.GANTT)} />
                                    <ToolButton icon={Beaker} label="The Lab" subLabel="A/B Testing" color="#D946EF" onClick={() => addCard(CardType.ADS_TEST)} />
                                </div>
                            </div>

                            {/* Production */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-100">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Production</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Film} label="Storyboard" subLabel="Visual sequencing" color="#10B981" onClick={() => addCard(CardType.FILMSTRIP)} />
                                    <ToolButton icon={FileText} label="Script" subLabel="A/V dual column" color="#6B7280" onClick={() => addCard(CardType.AV_SCRIPT)} />
                                    <ToolButton icon={ClipboardList} label="Call Sheet" subLabel="Shoot logistics" color="#F59E0B" onClick={() => addCard(CardType.CALL_SHEET)} />
                                    <ToolButton icon={Users} label="Casting" subLabel="Talent management" color="#EC4899" onClick={() => addCard(CardType.CASTING_BOARD)} />
                                    <ToolButton icon={Package} label="Props" subLabel="Inventory list" color="#6366F1" onClick={() => addCard(CardType.PROP_TABLE)} />
                                </div>
                            </div>

                            {/* Connectors */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-150">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Connectors</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={LayoutGrid} label="Grid Planner" subLabel="Instagram layout" color="#0EA5E9" onClick={() => addCard(CardType.GRID_PLANNER)} />
                                    <ToolButton icon={LinkIcon} label="Pinterest" subLabel="Board integration" color="#E60023" onClick={() => addCard(CardType.PINTEREST)} />
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, color, onClick }: { icon: any, label: string, subLabel: string, color: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className={`w-10 h-10 rounded-xl flex items-center justify-center shadow-sm text-white shrink-0`} style={{ backgroundColor: color }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-gray-100/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Restored High Fidelity List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">

                            {/* Essentials */}
                            <div className="animate-in slide-in-from-left-4 duration-300">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Essentials</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={ImageIcon} label="Post Card" subLabel="Social content & assets" color="#3A5C34" onClick={() => addCard(CardType.POST)} />
                                    <ToolButton icon={Type} label="Typography" subLabel="Headings & notes" color="#1C1C1E" onClick={() => setActiveTool('TEXT')} />
                                    <ToolButton icon={StickyNote} label="Sticky Note" subLabel="Quick thoughts" color="#FFD753" onClick={() => setActiveTool('STICKY')} />
                                    <ToolButton icon={Mail} label="Newsletter" subLabel="Email campaigns" color="#5F2427" onClick={() => addCard(CardType.NEWSLETTER)} />
                                </div>
                            </div>

                            {/* Strategy */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-75">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Strategy</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Sparkles} label="Oracle AI" subLabel="Generate hooks & ideas" color="#8B5CF6" onClick={() => addCard(CardType.STRATEGY_AI)} />
                                    <ToolButton icon={BarChart2} label="Analytics" subLabel="KPI tracking" color="#007AFF" onClick={() => addCard(CardType.ANALYTICS)} />
                                    <ToolButton icon={CalendarRange} label="Timeline" subLabel="Gantt chart" color="#FF9500" onClick={() => addCard(CardType.GANTT)} />
                                    <ToolButton icon={Beaker} label="The Lab" subLabel="A/B Testing" color="#D946EF" onClick={() => addCard(CardType.ADS_TEST)} />
                                </div>
                            </div>

                            {/* Production */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-100">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Production</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Film} label="Storyboard" subLabel="Visual sequencing" color="#10B981" onClick={() => addCard(CardType.FILMSTRIP)} />
                                    <ToolButton icon={FileText} label="Script" subLabel="A/V dual column" color="#6B7280" onClick={() => addCard(CardType.AV_SCRIPT)} />
                                    <ToolButton icon={ClipboardList} label="Call Sheet" subLabel="Shoot logistics" color="#F59E0B" onClick={() => addCard(CardType.CALL_SHEET)} />
                                    <ToolButton icon={Users} label="Casting" subLabel="Talent management" color="#EC4899" onClick={() => addCard(CardType.CASTING_BOARD)} />
                                    <ToolButton icon={Package} label="Props" subLabel="Inventory list" color="#6366F1" onClick={() => addCard(CardType.PROP_TABLE)} />
                                </div>
                            </div>

                            {/* Connectors */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-150">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Connectors</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={LayoutGrid} label="Grid Planner" subLabel="Instagram layout" color="#0EA5E9" onClick={() => addCard(CardType.GRID_PLANNER)} />
                                    <ToolButton icon={LinkIcon} label="Pinterest" subLabel="Board integration" color="#E60023" onClick={() => addCard(CardType.PINTEREST)} />
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }: { icon: any, label: string, subLabel: string, bgColor: string, iconColor: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-gray-100/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Restored High Fidelity List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">

                            {/* Essentials */}
                            <div className="animate-in slide-in-from-left-4 duration-300">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Essentials</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={ImageIcon} label="Post Card" subLabel="Social content & assets" bgColor={P.GREEN} iconColor={P.YELLOW} onClick={() => addCard(CardType.POST)} />
                                    <ToolButton icon={Type} label="Typography" subLabel="Headings & notes" bgColor={P.PEACH} iconColor={P.BURGUNDY} onClick={() => setActiveTool('TEXT')} />
                                    <ToolButton icon={StickyNote} label="Sticky Note" subLabel="Quick thoughts" bgColor={P.YELLOW} iconColor={P.GREEN} onClick={() => setActiveTool('STICKY')} />
                                    <ToolButton icon={Mail} label="Newsletter" subLabel="Email campaigns" bgColor={P.BURGUNDY} iconColor={P.PINK} onClick={() => addCard(CardType.NEWSLETTER)} />
                                </div>
                            </div>

                            {/* Strategy */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-75">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Strategy</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Sparkles} label="Oracle AI" subLabel="Generate hooks & ideas" bgColor={P.PINK} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.STRATEGY_AI)} />
                                    <ToolButton icon={BarChart2} label="Analytics" subLabel="KPI tracking" bgColor={P.GREEN} iconColor={P.PEACH} onClick={() => addCard(CardType.ANALYTICS)} />
                                    <ToolButton icon={CalendarRange} label="Timeline" subLabel="Gantt chart" bgColor={P.YELLOW} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.GANTT)} />
                                    <ToolButton icon={Beaker} label="The Lab" subLabel="A/B Testing" bgColor={P.BURGUNDY} iconColor={P.YELLOW} onClick={() => addCard(CardType.ADS_TEST)} />
                                </div>
                            </div>

                            {/* Production */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-100">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Production</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Film} label="Storyboard" subLabel="Visual sequencing" bgColor={P.PEACH} iconColor={P.GREEN} onClick={() => addCard(CardType.FILMSTRIP)} />
                                    <ToolButton icon={FileText} label="Script" subLabel="A/V dual column" bgColor={P.PINK} iconColor={P.GREEN} onClick={() => addCard(CardType.AV_SCRIPT)} />
                                    <ToolButton icon={ClipboardList} label="Call Sheet" subLabel="Shoot logistics" bgColor={P.GREEN} iconColor={P.PINK} onClick={() => addCard(CardType.CALL_SHEET)} />
                                    <ToolButton icon={Users} label="Casting" subLabel="Talent management" bgColor={P.YELLOW} iconColor={P.GREEN} onClick={() => addCard(CardType.CASTING_BOARD)} />
                                    <ToolButton icon={Package} label="Props" subLabel="Inventory list" bgColor={P.BURGUNDY} iconColor={P.PEACH} onClick={() => addCard(CardType.PROP_TABLE)} />
                                </div>
                            </div>

                            {/* Connectors */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-150">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Connectors</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={LayoutGrid} label="Grid Planner" subLabel="Instagram layout" bgColor={P.PEACH} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.GRID_PLANNER)} />
                                    <ToolButton icon={LinkIcon} label="Pinterest" subLabel="Board integration" bgColor={P.PINK} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.PINTEREST)} />
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }: { icon: any, label: string, subLabel: string, bgColor: string, iconColor: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-[#FFD753]/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Restored High Fidelity List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">

                            {/* Essentials */}
                            <div className="animate-in slide-in-from-left-4 duration-300">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Essentials</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={ImageIcon} label="Post Card" subLabel="Social content & assets" bgColor={P.GREEN} iconColor={P.YELLOW} onClick={() => addCard(CardType.POST)} />
                                    <ToolButton icon={Type} label="Typography" subLabel="Headings & notes" bgColor={P.PEACH} iconColor={P.BURGUNDY} onClick={() => setActiveTool('TEXT')} />
                                    <ToolButton icon={StickyNote} label="Sticky Note" subLabel="Quick thoughts" bgColor={P.YELLOW} iconColor={P.GREEN} onClick={() => setActiveTool('STICKY')} />
                                    <ToolButton icon={Mail} label="Newsletter" subLabel="Email campaigns" bgColor={P.BURGUNDY} iconColor={P.PINK} onClick={() => addCard(CardType.NEWSLETTER)} />
                                </div>
                            </div>

                            {/* Strategy */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-75">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Strategy</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Sparkles} label="Oracle AI" subLabel="Generate hooks & ideas" bgColor={P.PINK} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.STRATEGY_AI)} />
                                    <ToolButton icon={BarChart2} label="Analytics" subLabel="KPI tracking" bgColor={P.GREEN} iconColor={P.PEACH} onClick={() => addCard(CardType.ANALYTICS)} />
                                    <ToolButton icon={CalendarRange} label="Timeline" subLabel="Gantt chart" bgColor={P.YELLOW} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.GANTT)} />
                                    <ToolButton icon={Beaker} label="The Lab" subLabel="A/B Testing" bgColor={P.BURGUNDY} iconColor={P.YELLOW} onClick={() => addCard(CardType.ADS_TEST)} />
                                </div>
                            </div>

                            {/* Production */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-100">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Production</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={Film} label="Storyboard" subLabel="Visual sequencing" bgColor={P.PEACH} iconColor={P.GREEN} onClick={() => addCard(CardType.FILMSTRIP)} />
                                    <ToolButton icon={FileText} label="Script" subLabel="A/V dual column" bgColor={P.PINK} iconColor={P.GREEN} onClick={() => addCard(CardType.AV_SCRIPT)} />
                                    <ToolButton icon={ClipboardList} label="Call Sheet" subLabel="Shoot logistics" bgColor={P.GREEN} iconColor={P.PINK} onClick={() => addCard(CardType.CALL_SHEET)} />
                                    <ToolButton icon={Users} label="Casting" subLabel="Talent management" bgColor={P.YELLOW} iconColor={P.GREEN} onClick={() => addCard(CardType.CASTING_BOARD)} />
                                    <ToolButton icon={Package} label="Props" subLabel="Inventory list" bgColor={P.BURGUNDY} iconColor={P.PEACH} onClick={() => addCard(CardType.PROP_TABLE)} />
                                </div>
                            </div>

                            {/* Connectors */}
                            <div className="animate-in slide-in-from-left-4 duration-300 delay-150">
                                <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">Connectors</h3>
                                <div className="space-y-1">
                                    <ToolButton icon={LayoutGrid} label="Grid Planner" subLabel="Instagram layout" bgColor={P.PEACH} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.GRID_PLANNER)} />
                                    <ToolButton icon={LinkIcon} label="Pinterest" subLabel="Board integration" bgColor={P.PINK} iconColor={P.BURGUNDY} onClick={() => addCard(CardType.PINTEREST)} />
                                </div>
                            </div>

                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker, Archive
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER TOOLS DATA STRUCTURE ---
  const toolsData = [
    { 
      category: 'Essentials',
      items: [
        { icon: ImageIcon, label: "Post Card", subLabel: "Social content & assets", bgColor: P.GREEN, iconColor: P.YELLOW, action: () => addCard(CardType.POST) },
        { icon: Type, label: "Typography", subLabel: "Headings & notes", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => setActiveTool('TEXT') },
        { icon: StickyNote, label: "Sticky Note", subLabel: "Quick thoughts", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => setActiveTool('STICKY') },
        { icon: Mail, label: "Newsletter", subLabel: "Email campaigns", bgColor: P.BURGUNDY, iconColor: P.PINK, action: () => addCard(CardType.NEWSLETTER) },
      ]
    },
    {
      category: 'Strategy',
      items: [
        { icon: Sparkles, label: "Oracle AI", subLabel: "Generate hooks & ideas", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.STRATEGY_AI) },
        { icon: BarChart2, label: "Analytics", subLabel: "KPI tracking", bgColor: P.GREEN, iconColor: P.PEACH, action: () => addCard(CardType.ANALYTICS) },
        { icon: CalendarRange, label: "Timeline", subLabel: "Gantt chart", bgColor: P.YELLOW, iconColor: P.BURGUNDY, action: () => addCard(CardType.GANTT) },
        { icon: Beaker, label: "The Lab", subLabel: "A/B Testing", bgColor: P.BURGUNDY, iconColor: P.YELLOW, action: () => addCard(CardType.ADS_TEST) },
      ]
    },
    {
      category: 'Production',
      items: [
        { icon: Film, label: "Storyboard", subLabel: "Visual sequencing", bgColor: P.PEACH, iconColor: P.GREEN, action: () => addCard(CardType.FILMSTRIP) },
        { icon: FileText, label: "Script", subLabel: "A/V dual column", bgColor: P.PINK, iconColor: P.GREEN, action: () => addCard(CardType.AV_SCRIPT) },
        { icon: ClipboardList, label: "Call Sheet", subLabel: "Shoot logistics", bgColor: P.GREEN, iconColor: P.PINK, action: () => addCard(CardType.CALL_SHEET) },
        { icon: Users, label: "Casting", subLabel: "Talent management", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => addCard(CardType.CASTING_BOARD) },
        { icon: Package, label: "Props", subLabel: "Inventory list", bgColor: P.BURGUNDY, iconColor: P.PEACH, action: () => addCard(CardType.PROP_TABLE) },
      ]
    },
    {
      category: 'Connectors',
      items: [
        { icon: LayoutGrid, label: "Grid Planner", subLabel: "Instagram layout", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => addCard(CardType.GRID_PLANNER) },
        { icon: LinkIcon, label: "Pinterest", subLabel: "Board integration", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.PINTEREST) },
      ]
    }
  ];

  // --- FILTERING LOGIC ---
  const displayedTools = useMemo(() => {
    if (!searchTerm.trim()) return toolsData;
    const lowerTerm = searchTerm.toLowerCase();

    // Flatten and filter
    const flatItems = toolsData.flatMap(cat => cat.items).filter(item => 
        item.label.toLowerCase().includes(lowerTerm) || 
        item.subLabel.toLowerCase().includes(lowerTerm)
    );

    return flatItems.length > 0 
      ? [{ category: 'Search Results', items: flatItems }]
      : [];
  }, [searchTerm, toolsData]); // toolsData is effectively constant here since it's defined in render scope but action closures are fresh

  // --- DRAWER COMPONENT ---
  const ToolButton = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }: { icon: any, label: string, subLabel: string, bgColor: string, iconColor: string, onClick: () => void }) => (
    <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
      <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
        <Icon size={20} />
      </div>
      <div className="flex flex-col min-w-0">
        <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
        <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
      </div>
    </button>
  );

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-[#FFD753]/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Filtered List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">
                            {displayedTools.length > 0 ? (
                                displayedTools.map((category, idx) => (
                                    <div key={idx} className="animate-in slide-in-from-left-4 duration-300" style={{ animationDelay: `${idx * 75}ms` }}>
                                        <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">{category.category}</h3>
                                        <div className="space-y-1">
                                            {category.items.map((tool, tIdx) => (
                                                <ToolButton 
                                                    key={tIdx} 
                                                    icon={tool.icon} 
                                                    label={tool.label} 
                                                    subLabel={tool.subLabel} 
                                                    bgColor={tool.bgColor} 
                                                    iconColor={tool.iconColor} 
                                                    onClick={tool.action} 
                                                />
                                            ))}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="flex flex-col items-center justify-center h-40 text-gray-400 text-center px-4">
                                    <Archive size={32} className="mb-2 opacity-20" />
                                    <p className="text-[13px] font-medium">No tools found</p>
                                    <p className="text-[11px]">Try searching for something else.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker, Archive
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

interface ToolButtonProps {
  icon: any;
  label: string;
  subLabel: string;
  bgColor: string;
  iconColor: string;
  onClick: () => void;
}

// --- DRAWER COMPONENT ---
const ToolButton: React.FC<ToolButtonProps> = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }) => (
  <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
    <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
      <Icon size={20} />
    </div>
    <div className="flex flex-col min-w-0">
      <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
      <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
    </div>
  </button>
);

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;
      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);
      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode]);

  // --- DRAWER TOOLS DATA STRUCTURE ---
  const toolsData = [
    { 
      category: 'Essentials',
      items: [
        { icon: ImageIcon, label: "Post Card", subLabel: "Social content & assets", bgColor: P.GREEN, iconColor: P.YELLOW, action: () => addCard(CardType.POST) },
        { icon: Type, label: "Typography", subLabel: "Headings & notes", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => setActiveTool('TEXT') },
        { icon: StickyNote, label: "Sticky Note", subLabel: "Quick thoughts", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => setActiveTool('STICKY') },
        { icon: Mail, label: "Newsletter", subLabel: "Email campaigns", bgColor: P.BURGUNDY, iconColor: P.PINK, action: () => addCard(CardType.NEWSLETTER) },
      ]
    },
    {
      category: 'Strategy',
      items: [
        { icon: Sparkles, label: "Oracle AI", subLabel: "Generate hooks & ideas", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.STRATEGY_AI) },
        { icon: BarChart2, label: "Analytics", subLabel: "KPI tracking", bgColor: P.GREEN, iconColor: P.PEACH, action: () => addCard(CardType.ANALYTICS) },
        { icon: CalendarRange, label: "Timeline", subLabel: "Gantt chart", bgColor: P.YELLOW, iconColor: P.BURGUNDY, action: () => addCard(CardType.GANTT) },
        { icon: Beaker, label: "The Lab", subLabel: "A/B Testing", bgColor: P.BURGUNDY, iconColor: P.YELLOW, action: () => addCard(CardType.ADS_TEST) },
      ]
    },
    {
      category: 'Production',
      items: [
        { icon: Film, label: "Storyboard", subLabel: "Visual sequencing", bgColor: P.PEACH, iconColor: P.GREEN, action: () => addCard(CardType.FILMSTRIP) },
        { icon: FileText, label: "Script", subLabel: "A/V dual column", bgColor: P.PINK, iconColor: P.GREEN, action: () => addCard(CardType.AV_SCRIPT) },
        { icon: ClipboardList, label: "Call Sheet", subLabel: "Shoot logistics", bgColor: P.GREEN, iconColor: P.PINK, action: () => addCard(CardType.CALL_SHEET) },
        { icon: Users, label: "Casting", subLabel: "Talent management", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => addCard(CardType.CASTING_BOARD) },
        { icon: Package, label: "Props", subLabel: "Inventory list", bgColor: P.BURGUNDY, iconColor: P.PEACH, action: () => addCard(CardType.PROP_TABLE) },
      ]
    },
    {
      category: 'Connectors',
      items: [
        { icon: LayoutGrid, label: "Grid Planner", subLabel: "Instagram layout", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => addCard(CardType.GRID_PLANNER) },
        { icon: LinkIcon, label: "Pinterest", subLabel: "Board integration", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.PINTEREST) },
      ]
    }
  ];

  // --- FILTERING LOGIC ---
  const displayedTools = useMemo(() => {
    if (!searchTerm.trim()) return toolsData;
    const lowerTerm = searchTerm.toLowerCase();

    // Flatten and filter
    const flatItems = toolsData.flatMap(cat => cat.items).filter(item => 
        item.label.toLowerCase().includes(lowerTerm) || 
        item.subLabel.toLowerCase().includes(lowerTerm)
    );

    return flatItems.length > 0 
      ? [{ category: 'Search Results', items: flatItems }]
      : [];
  }, [searchTerm, toolsData]); // toolsData is effectively constant here since it's defined in render scope but action closures are fresh

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {isSyncing && (
                        <div className="px-3 h-8 flex items-center gap-2 bg-white/80 backdrop-blur rounded-lg border border-gray-100 shadow-sm animate-in fade-in">
                            <Cloud size={14} className="text-[#3A5C34] animate-pulse" />
                            <span className="text-[11px] font-medium text-gray-500">Saving...</span>
                        </div>
                    )}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all"><LogOut size={18} strokeWidth={2.5} className="ml-0.5" /></button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-[#FFD753]/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Filtered List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">
                            {displayedTools.length > 0 ? (
                                displayedTools.map((category, idx) => (
                                    <div key={idx} className="animate-in slide-in-from-left-4 duration-300" style={{ animationDelay: `${idx * 75}ms` }}>
                                        <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">{category.category}</h3>
                                        <div className="space-y-1">
                                            {category.items.map((tool, tIdx) => (
                                                <ToolButton 
                                                    key={tIdx} 
                                                    icon={tool.icon} 
                                                    label={tool.label} 
                                                    subLabel={tool.subLabel} 
                                                    bgColor={tool.bgColor} 
                                                    iconColor={tool.iconColor} 
                                                    onClick={tool.action} 
                                                />
                                            ))}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="flex flex-col items-center justify-center h-40 text-gray-400 text-center px-4">
                                    <Archive size={32} className="mb-2 opacity-20" />
                                    <p className="text-[13px] font-medium">No tools found</p>
                                    <p className="text-[11px]">Try searching for something else.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker, Archive
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

interface ToolButtonProps {
  icon: any;
  label: string;
  subLabel: string;
  bgColor: string;
  iconColor: string;
  onClick: () => void;
}

// --- DRAWER COMPONENT ---
const ToolButton: React.FC<ToolButtonProps> = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }) => (
  <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
    <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
      <Icon size={20} />
    </div>
    <div className="flex flex-col min-w-0">
      <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
      <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
    </div>
  </button>
);

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  // Undo/Redo Handlers
  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    const newHistory = history.slice(0, -1);
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(newHistory);

    // Update without pushing to history again
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: previous } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(newFuture);

    // Update without pushing to history again
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: next } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);

      // Undo/Redo Shortcuts
      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
          if (e.shiftKey) {
              e.preventDefault();
              handleRedo();
          } else {
              e.preventDefault();
              handleUndo();
          }
      }

      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode, history, future]);

  // --- DRAWER TOOLS DATA STRUCTURE ---
  const toolsData = [
    { 
      category: 'Essentials',
      items: [
        { icon: ImageIcon, label: "Post Card", subLabel: "Social content & assets", bgColor: P.GREEN, iconColor: P.YELLOW, action: () => addCard(CardType.POST) },
        { icon: Type, label: "Typography", subLabel: "Headings & notes", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => setActiveTool('TEXT') },
        { icon: StickyNote, label: "Sticky Note", subLabel: "Quick thoughts", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => setActiveTool('STICKY') },
        { icon: Mail, label: "Newsletter", subLabel: "Email campaigns", bgColor: P.BURGUNDY, iconColor: P.PINK, action: () => addCard(CardType.NEWSLETTER) },
      ]
    },
    {
      category: 'Strategy',
      items: [
        { icon: Sparkles, label: "Oracle AI", subLabel: "Generate hooks & ideas", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.STRATEGY_AI) },
        { icon: BarChart2, label: "Analytics", subLabel: "KPI tracking", bgColor: P.GREEN, iconColor: P.PEACH, action: () => addCard(CardType.ANALYTICS) },
        { icon: CalendarRange, label: "Timeline", subLabel: "Gantt chart", bgColor: P.YELLOW, iconColor: P.BURGUNDY, action: () => addCard(CardType.GANTT) },
        { icon: Beaker, label: "The Lab", subLabel: "A/B Testing", bgColor: P.BURGUNDY, iconColor: P.YELLOW, action: () => addCard(CardType.ADS_TEST) },
      ]
    },
    {
      category: 'Production',
      items: [
        { icon: Film, label: "Storyboard", subLabel: "Visual sequencing", bgColor: P.PEACH, iconColor: P.GREEN, action: () => addCard(CardType.FILMSTRIP) },
        { icon: FileText, label: "Script", subLabel: "A/V dual column", bgColor: P.PINK, iconColor: P.GREEN, action: () => addCard(CardType.AV_SCRIPT) },
        { icon: ClipboardList, label: "Call Sheet", subLabel: "Shoot logistics", bgColor: P.GREEN, iconColor: P.PINK, action: () => addCard(CardType.CALL_SHEET) },
        { icon: Users, label: "Casting", subLabel: "Talent management", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => addCard(CardType.CASTING_BOARD) },
        { icon: Package, label: "Props", subLabel: "Inventory list", bgColor: P.BURGUNDY, iconColor: P.PEACH, action: () => addCard(CardType.PROP_TABLE) },
      ]
    },
    {
      category: 'Connectors',
      items: [
        { icon: LayoutGrid, label: "Grid Planner", subLabel: "Instagram layout", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => addCard(CardType.GRID_PLANNER) },
        { icon: LinkIcon, label: "Pinterest", subLabel: "Board integration", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.PINTEREST) },
      ]
    }
  ];

  // --- FILTERING LOGIC ---
  const displayedTools = useMemo(() => {
    if (!searchTerm.trim()) return toolsData;
    const lowerTerm = searchTerm.toLowerCase();

    // Flatten and filter
    const flatItems = toolsData.flatMap(cat => cat.items).filter(item => 
        item.label.toLowerCase().includes(lowerTerm) || 
        item.subLabel.toLowerCase().includes(lowerTerm)
    );

    return flatItems.length > 0 
      ? [{ category: 'Search Results', items: flatItems }]
      : [];
  }, [searchTerm, toolsData]); // toolsData is effectively constant here since it's defined in render scope but action closures are fresh

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {/* Breadcrumbs */}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>

                    {/* Zoom / Undo / Redo Control Bar */}
                    <div className="h-10 px-3 flex items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm">
                        <span className="text-[13px] font-bold text-gray-700 min-w-[36px] text-center">
                            {Math.round(scale * 100)}%
                        </span>
                        <div className="w-px h-4 bg-gray-200" />
                        <button 
                            onClick={handleUndo} 
                            disabled={history.length === 0}
                            className="p-1 rounded-md text-gray-500 hover:text-gray-900 hover:bg-gray-100 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        >
                            <Undo2 size={16} />
                        </button>
                        <button 
                            onClick={handleRedo}
                            disabled={future.length === 0}
                            className="p-1 rounded-md text-gray-500 hover:text-gray-900 hover:bg-gray-100 disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        >
                            <Redo2 size={16} />
                        </button>
                    </div>

                    {/* Exit Button */}
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all">
                        <LogOut size={18} strokeWidth={2.5} className="ml-0.5" />
                    </button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-[#FFD753]/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Filtered List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">
                            {displayedTools.length > 0 ? (
                                displayedTools.map((category, idx) => (
                                    <div key={idx} className="animate-in slide-in-from-left-4 duration-300" style={{ animationDelay: `${idx * 75}ms` }}>
                                        <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">{category.category}</h3>
                                        <div className="space-y-1">
                                            {category.items.map((tool, tIdx) => (
                                                <ToolButton 
                                                    key={tIdx} 
                                                    icon={tool.icon} 
                                                    label={tool.label} 
                                                    subLabel={tool.subLabel} 
                                                    bgColor={tool.bgColor} 
                                                    iconColor={tool.iconColor} 
                                                    onClick={tool.action} 
                                                />
                                            ))}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="flex flex-col items-center justify-center h-40 text-gray-400 text-center px-4">
                                    <Archive size={32} className="mb-2 opacity-20" />
                                    <p className="text-[13px] font-medium">No tools found</p>
                                    <p className="text-[11px]">Try searching for something else.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, CardType, Workspace, ToolType, FileSystemNode, NodeType, Position, UserProfile, Brand } from './types';
import { Canvas } from './components/Canvas';
import { DrawingToolbar } from './components/ui/DrawingToolbar';
import { Sidebar } from './components/Sidebar';
import { PageView } from './components/PageView';
import { saveNodesToSupabase, loadNodesFromSupabase, supabase, getUserProfile, getUserBrand, updateUserProfile } from './services/supabase';
import { soundService } from './services/soundService';
import { LoginForm } from './components/auth/LoginForm';
import { RegisterForm } from './components/auth/RegisterForm';
import { OnboardingFlow } from './components/auth/OnboardingFlow';
import { 
  Loader2, Plus, Search, ChevronDown, Check, Trash2, Undo2, Redo2, Menu, LogOut, ArrowRight, Save, Cloud, 
  Sparkles, FileText, StickyNote, Image as ImageIcon, Link as LinkIcon, BarChart2, LayoutGrid, Palette, Users, Clock, Mail,
  Video, Mic, ClipboardList, Package, Film, Type, MousePointer2, GripHorizontal, CalendarRange, Beaker, Archive
} from 'lucide-react';

// --- CONSTANTS ---
const DEFAULT_WHITEBOARD_DATA: Workspace[] = [
  { id: 'tab-1', name: 'Main Board', color: '#3A5C34', cards: [] }
];

const TAB_COLORS = [
  '#3A5C34', '#FFD753', '#FCCAE2', '#5F2427', '#007AFF', '#FF9500', '#8E8E93'
];

// App Palette
const P = {
  PEACH: '#F9E6D1',
  YELLOW: '#FFD753',
  GREEN: '#3A5C34',
  PINK: '#FCCAE2',
  BURGUNDY: '#5F2427'
};

const getTabTheme = (baseColor: string | undefined) => {
    const color = baseColor || '#5F2427';
    switch (color) {
        case '#FFD753': return { text: '#854D0E', bg: color };
        case '#FCCAE2': return { text: '#9D174D', bg: color };
        case '#FF9500': return { text: '#C2410C', bg: color };
        default: return { text: color, bg: color };
    }
};

interface ToolButtonProps {
  icon: any;
  label: string;
  subLabel: string;
  bgColor: string;
  iconColor: string;
  onClick: () => void;
}

// --- DRAWER COMPONENT ---
const ToolButton: React.FC<ToolButtonProps> = ({ icon: Icon, label, subLabel, bgColor, iconColor, onClick }) => (
  <button onClick={onClick} className="flex items-center gap-3 p-2.5 w-full rounded-2xl hover:bg-gray-50 border border-transparent hover:border-gray-200 transition-all group text-left">
    <div className="w-10 h-10 rounded-xl flex items-center justify-center shadow-sm shrink-0" style={{ backgroundColor: bgColor, color: iconColor }}>
      <Icon size={20} />
    </div>
    <div className="flex flex-col min-w-0">
      <span className="text-[13px] font-semibold text-gray-900 leading-tight group-hover:text-[#5F2427] truncate">{label}</span>
      <span className="text-[11px] text-gray-400 leading-tight truncate">{subLabel}</span>
    </div>
  </button>
);

export default function App() {
  // --- Auth & Gatekeeper State ---
  const [session, setSession] = useState<any>(null);
  const [authLoading, setAuthLoading] = useState(true);
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [onboardingComplete, setOnboardingComplete] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [brand, setBrand] = useState<Brand | null>(null);

  // --- Main App State ---
  const [nodes, setNodes] = useState<Record<string, FileSystemNode>>({});
  const [activeNodeId, setActiveNodeId] = useState<string>('root');
  const [isSyncing, setIsSyncing] = useState(false);

  // --- Whiteboard State ---
  const [workspaces, setWorkspaces] = useState<Workspace[]>(DEFAULT_WHITEBOARD_DATA);
  const [activeWorkspaceId, setActiveWorkspaceId] = useState<string>('tab-1');
  const [hoveredTabId, setHoveredTabId] = useState<string | null>(null);

  const [activeTool, setActiveTool] = useState<ToolType>('SELECT');
  const [scale, setScale] = useState(1);
  const [pan, setPan] = useState<Position>({ x: 0, y: 0 });
  const [isSpacePressed, setIsSpacePressed] = useState(false);

  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [colorPickerState, setColorPickerState] = useState<{ id: string; x: number; y: number } | null>(null);
  const [editingTabId, setEditingTabId] = useState<string | null>(null);
  const [editTabName, setEditTabName] = useState("");
  const [isRenamingTitle, setIsRenamingTitle] = useState(false);
  const [titleInputValue, setTitleInputValue] = useState("");

  const [history, setHistory] = useState<CardData[][]>([]);
  const [future, setFuture] = useState<CardData[][]>([]);

  // --- AUTH CHECKER ---
  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) checkOnboarding(session.user.id);
      else setAuthLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const checkOnboarding = async (userId: string) => {
    const profile = await getUserProfile(userId);
    const userBrand = await getUserBrand(userId);
    setUserProfile(profile);
    setBrand(userBrand);
    if (profile) setOnboardingComplete(profile.onboarding_complete);
    setAuthLoading(false);
  };

  // --- CLEAN SLATE & INITIALIZATION ---
  useEffect(() => {
    if (!session || !onboardingComplete) return;

    const load = async () => {
      setIsSyncing(true);
      const savedNodes = await loadNodesFromSupabase();

      if (savedNodes && Object.keys(savedNodes).length > 0) {
        setNodes(savedNodes);
      } else {
        const defaultNodes: Record<string, FileSystemNode> = {
            'folder-campaigns': { id: 'folder-campaigns', type: 'folder', name: 'Campaigns', parentId: null, order: 0, description: 'Launch calendars and seasonal events' },
            'folder-channels': { id: 'folder-channels', type: 'folder', name: 'Channels', parentId: null, order: 1, description: 'Social, Email, and Blog content' },
            'folder-paid': { id: 'folder-paid', type: 'folder', name: 'Paid Media', parentId: null, order: 2, description: 'Ad creative and performance' },
            'folder-assets': { id: 'folder-assets', type: 'folder', name: 'Brand Assets', parentId: null, order: 3, description: 'Guidelines and core assets' },
            'folder-creative': { id: 'folder-creative', type: 'folder', name: 'Creative Library', parentId: null, order: 4, description: 'Work in progress' },
            'folder-reports': { id: 'folder-reports', type: 'folder', name: 'Insights & Reports', parentId: null, order: 5, description: 'Analytics and research' },
        };
        setNodes(defaultNodes);
        await saveNodesToSupabase(defaultNodes);
      }
      setIsSyncing(false);
    };
    load();
  }, [session, onboardingComplete]);

  useEffect(() => {
    if (!session || !onboardingComplete) return;
    setIsSyncing(true);
    const timer = setTimeout(() => {
      saveNodesToSupabase(nodes).then(() => setIsSyncing(false));
    }, 2000);
    return () => clearTimeout(timer);
  }, [nodes, session, onboardingComplete]);

  // --- HELPER HANDLERS (IMPLEMENTED IN SCOPE) ---
  const handleCreateNode = (type: NodeType, parentId: string | null) => {
    const id = `${type}-${Date.now()}`;
    // Determine effective parent
    let effectiveParentId = parentId;
    if (!effectiveParentId && activeNodeId !== 'root' && activeNodeId !== 'recents' && activeNodeId !== 'favorites' && nodes[activeNodeId]?.type === 'folder') {
        effectiveParentId = activeNodeId;
    } else if (!effectiveParentId && (activeNodeId === 'root' || activeNodeId === 'recents' || activeNodeId === 'favorites')) {
        effectiveParentId = null;
    }

    const newNode: FileSystemNode = {
        id,
        type,
        name: type === 'folder' ? 'New Folder' : 'Untitled Whiteboard',
        parentId: effectiveParentId,
        order: Date.now(),
        whiteboardData: type === 'whiteboard' ? DEFAULT_WHITEBOARD_DATA : undefined
    };

    setNodes(prev => ({ ...prev, [id]: newNode }));

    // Auto-navigate if whiteboard
    if (type === 'whiteboard') {
        handleNavigate(id);
    }
  };

  const handleUpdateNode = (id: string, updates: Partial<FileSystemNode>) => {
      setNodes(prev => ({
          ...prev,
          [id]: { ...prev[id], ...updates }
      }));
  };

  const handleDeleteNode = (id: string) => {
      setNodes(prev => {
          const next = { ...prev };
          delete next[id];
          return next;
      });
      if (activeNodeId === id) handleNavigate('root');
  };

  const handleMoveNode = (dragId: string, targetId: string) => {
      if (dragId === targetId) return;

      const targetNode = nodes[targetId];
      let newParentId: string | null = null;

      if (targetId === 'root') {
          newParentId = null;
      } else if (targetNode && targetNode.type === 'folder') {
          newParentId = targetId;
      } else if (targetNode) {
          // Dropped on a file? Move to that file's parent (sibling reorder intent usually)
          newParentId = targetNode.parentId;
      }

      setNodes(prev => ({
          ...prev,
          [dragId]: { ...prev[dragId], parentId: newParentId }
      }));
  };

  const handleReorderNode = (dragId: string, targetId: string) => {
      handleMoveNode(dragId, targetId);
  };

  const handleExitWhiteboard = () => {
    if (realNode && realNode.parentId) {
        handleNavigate(realNode.parentId);
    } else {
        handleNavigate('root');
    }
  };

  const toggleColorPicker = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (colorPickerState?.id === id) {
        setColorPickerState(null);
    } else {
        const rect = e.currentTarget.getBoundingClientRect();
        setColorPickerState({ id, x: rect.left + rect.width / 2, y: rect.top });
    }
  };

  const handleDismissTour = async () => {
      if (!session?.user?.id) return;
      try {
          await updateUserProfile(session.user.id, { tour_completed: true });
          if (userProfile) setUserProfile({ ...userProfile, tour_completed: true });
      } catch (e) { console.error("Failed to dismiss tour", e); }
  };

  const isSpecialView = ['root', 'recents', 'favorites'].includes(activeNodeId);
  const realNode = nodes[activeNodeId];
  const isWhiteboardMode = realNode?.type === 'whiteboard';
  const activeWorkspace = workspaces.find(w => w.id === activeWorkspaceId) || workspaces[0];

  let displayedNode: FileSystemNode;
  let displayedChildren: FileSystemNode[] = [];
  const getSortedChildren = (filterFn: (n: FileSystemNode) => boolean) => {
      return (Object.values(nodes) as FileSystemNode[]).filter(filterFn).sort((a, b) => (a.order || 0) - (b.order || 0));
  };

  if (activeNodeId === 'root') {
    displayedNode = { id: 'root', type: 'folder', name: 'Home', parentId: null };
    displayedChildren = getSortedChildren(n => n.parentId === null);
  } else if (activeNodeId === 'recents') {
    displayedNode = { id: 'recents', type: 'folder', name: 'Recents', parentId: null };
    displayedChildren = (Object.values(nodes) as FileSystemNode[]).filter(n => n.type !== 'folder');
  } else if (activeNodeId === 'favorites') {
    displayedNode = { id: 'favorites', type: 'folder', name: 'Favorites', parentId: null };
    displayedChildren = getSortedChildren(n => !!n.isFavorite);
  } else if (realNode) {
    displayedNode = realNode;
    displayedChildren = getSortedChildren(n => n.parentId === activeNodeId);
  } else {
    displayedNode = { id: 'error', type: 'folder', name: 'Not Found', parentId: null };
  }

  const handleNavigate = (id: string) => {
    if (isWhiteboardMode && nodes[activeNodeId]) {
        setNodes(prev => ({
            ...prev,
            [activeNodeId]: { ...prev[activeNodeId], whiteboardData: workspaces }
        }));
    }
    const targetNode = nodes[id];
    if (targetNode && targetNode.type === 'whiteboard') {
        if (targetNode.whiteboardData) {
            setWorkspaces(targetNode.whiteboardData);
            setActiveWorkspaceId(targetNode.whiteboardData[0]?.id || 'tab-1');
        } else {
            setWorkspaces(DEFAULT_WHITEBOARD_DATA);
            setActiveWorkspaceId('tab-1');
        }
    }
    setActiveNodeId(id);
    setScale(1);
    setPan({ x: 0, y: 0 });
    setHistory([]);
    setFuture([]);
  };

  const updateCards = (newCards: CardData[]) => {
    setHistory(prev => [...prev.slice(-20), activeWorkspace.cards]);
    setFuture([]);
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: newCards } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  // Undo/Redo Handlers
  const handleUndo = () => {
    if (history.length === 0) return;
    const previous = history[history.length - 1];
    const newHistory = history.slice(0, -1);
    setFuture(prev => [activeWorkspace.cards, ...prev]);
    setHistory(newHistory);

    // Update without pushing to history again
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: previous } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const handleRedo = () => {
    if (future.length === 0) return;
    const next = future[0];
    const newFuture = future.slice(1);
    setHistory(prev => [...prev, activeWorkspace.cards]);
    setFuture(newFuture);

    // Update without pushing to history again
    const updatedWorkspaces = workspaces.map(w => w.id === activeWorkspaceId ? { ...w, cards: next } : w);
    setWorkspaces(updatedWorkspaces);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updatedWorkspaces } }));
  };

  const addCard = (type: CardType, props: any = {}) => {
    soundService.play('drop');
    // Calculate center of current view
    const centerX = (window.innerWidth / 2 - pan.x) / scale - 150;
    const centerY = (window.innerHeight / 2 - pan.y) / scale - 100;

    const newCard: CardData = {
        id: `card-${Date.now()}`,
        type,
        x: centerX,
        y: centerY,
        width: 340,
        height: 400,
        zIndex: 10,
        content: props,
        ...props // Spread geometry overrides if any
    };
    updateCards([...activeWorkspace.cards, newCard]);
    setIsDrawerOpen(false);
  };

  // --- Handlers for Drawer Logic ---
  const addTab = () => {
    soundService.play('drop');
    const newWs: Workspace = { id: `tab-${Date.now()}`, name: `Sheet ${workspaces.length + 1}`, cards: [], color: TAB_COLORS[workspaces.length % TAB_COLORS.length] };
    const updated = [...workspaces, newWs];
    setWorkspaces(updated);
    setActiveWorkspaceId(newWs.id);
    setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };

  const updateTabName = (id: string, name: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, name } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const updateTabColor = (id: string, color: string) => {
      const updated = workspaces.map(w => w.id === id ? { ...w, color } : w);
      setWorkspaces(updated);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
  };
  const deleteTab = (id: string) => {
      if (workspaces.length <= 1) return;
      const updated = workspaces.filter(w => w.id !== id);
      setWorkspaces(updated);
      setActiveWorkspaceId(updated[0].id);
      setNodes(prev => ({ ...prev, [activeNodeId]: { ...prev[activeNodeId], whiteboardData: updated } }));
      setColorPickerState(null);
  };

  // --- SHORTCUTS & EVENTS ---
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      if (['INPUT', 'TEXTAREA'].includes(target.tagName) || target.isContentEditable) return;

      if (e.code === 'Space' && !e.repeat) setIsSpacePressed(true);

      // Undo/Redo Shortcuts
      if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
          if (e.shiftKey) {
              e.preventDefault();
              handleRedo();
          } else {
              e.preventDefault();
              handleUndo();
          }
      }

      if (!isSpacePressed && isWhiteboardMode) {
          if (e.key.toLowerCase() === 'v' || e.key === 'Escape') setActiveTool('SELECT');
          if (e.key.toLowerCase() === 'h') setActiveTool('PAN');
      }
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.code === 'Space') setIsSpacePressed(false);
    };
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [isSpacePressed, isWhiteboardMode, history, future]);

  // --- DRAWER TOOLS DATA STRUCTURE ---
  const toolsData = [
    { 
      category: 'Essentials',
      items: [
        { icon: ImageIcon, label: "Post Card", subLabel: "Social content & assets", bgColor: P.GREEN, iconColor: P.YELLOW, action: () => addCard(CardType.POST) },
        { icon: Type, label: "Typography", subLabel: "Headings & notes", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => setActiveTool('TEXT') },
        { icon: StickyNote, label: "Sticky Note", subLabel: "Quick thoughts", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => setActiveTool('STICKY') },
        { icon: Mail, label: "Newsletter", subLabel: "Email campaigns", bgColor: P.BURGUNDY, iconColor: P.PINK, action: () => addCard(CardType.NEWSLETTER) },
      ]
    },
    {
      category: 'Strategy',
      items: [
        { icon: Sparkles, label: "Oracle AI", subLabel: "Generate hooks & ideas", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.STRATEGY_AI) },
        { icon: BarChart2, label: "Analytics", subLabel: "KPI tracking", bgColor: P.GREEN, iconColor: P.PEACH, action: () => addCard(CardType.ANALYTICS) },
        { icon: CalendarRange, label: "Timeline", subLabel: "Gantt chart", bgColor: P.YELLOW, iconColor: P.BURGUNDY, action: () => addCard(CardType.GANTT) },
        { icon: Beaker, label: "The Lab", subLabel: "A/B Testing", bgColor: P.BURGUNDY, iconColor: P.YELLOW, action: () => addCard(CardType.ADS_TEST) },
      ]
    },
    {
      category: 'Production',
      items: [
        { icon: Film, label: "Storyboard", subLabel: "Visual sequencing", bgColor: P.PEACH, iconColor: P.GREEN, action: () => addCard(CardType.FILMSTRIP) },
        { icon: FileText, label: "Script", subLabel: "A/V dual column", bgColor: P.PINK, iconColor: P.GREEN, action: () => addCard(CardType.AV_SCRIPT) },
        { icon: ClipboardList, label: "Call Sheet", subLabel: "Shoot logistics", bgColor: P.GREEN, iconColor: P.PINK, action: () => addCard(CardType.CALL_SHEET) },
        { icon: Users, label: "Casting", subLabel: "Talent management", bgColor: P.YELLOW, iconColor: P.GREEN, action: () => addCard(CardType.CASTING_BOARD) },
        { icon: Package, label: "Props", subLabel: "Inventory list", bgColor: P.BURGUNDY, iconColor: P.PEACH, action: () => addCard(CardType.PROP_TABLE) },
      ]
    },
    {
      category: 'Connectors',
      items: [
        { icon: LayoutGrid, label: "Grid Planner", subLabel: "Instagram layout", bgColor: P.PEACH, iconColor: P.BURGUNDY, action: () => addCard(CardType.GRID_PLANNER) },
        { icon: LinkIcon, label: "Pinterest", subLabel: "Board integration", bgColor: P.PINK, iconColor: P.BURGUNDY, action: () => addCard(CardType.PINTEREST) },
      ]
    }
  ];

  // --- FILTERING LOGIC ---
  const displayedTools = useMemo(() => {
    if (!searchTerm.trim()) return toolsData;
    const lowerTerm = searchTerm.toLowerCase();

    // Flatten and filter
    const flatItems = toolsData.flatMap(cat => cat.items).filter(item => 
        item.label.toLowerCase().includes(lowerTerm) || 
        item.subLabel.toLowerCase().includes(lowerTerm)
    );

    return flatItems.length > 0 
      ? [{ category: 'Search Results', items: flatItems }]
      : [];
  }, [searchTerm, toolsData]); // toolsData is effectively constant here since it's defined in render scope but action closures are fresh

  // --- RENDER CONDITIONAL VIEWS ---
  if (authLoading) return <div className="h-screen w-full flex items-center justify-center bg-[#F9F8F6]"><Loader2 size={32} className="text-[#3A5C34] animate-spin" /></div>;
  if (!session) {
    if (authView === 'login') return <LoginForm onRegisterClick={() => setAuthView('register')} />;
    return <RegisterForm onLoginClick={() => setAuthView('login')} />;
  }
  if (!onboardingComplete) return <OnboardingFlow userId={session.user.id} onComplete={() => setOnboardingComplete(true)} />;

  // --- MAIN APP ---
  return (
    <div className="flex w-full h-screen bg-white text-[#1C1C1E] overflow-hidden font-sans">

      {/* Sidebar (Main Navigation) */}
      {isSidebarOpen && !isWhiteboardMode && (
        <Sidebar 
          nodes={nodes}
          activeNodeId={activeNodeId}
          userProfile={userProfile}
          brand={brand}
          onNavigate={handleNavigate}
          onToggleExpand={id => setNodes(prev => ({ ...prev, [id]: { ...prev[id], isExpanded: !prev[id].isExpanded } }))}
          onCreateNode={handleCreateNode}
          onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
          onMoveNode={handleMoveNode}
          onUpdateNode={handleUpdateNode}
          onDeleteNode={handleDeleteNode}
        />
      )}

      {/* Content Area */}
      <div className="flex-1 relative flex flex-col h-full min-w-0">
         {!isSidebarOpen && !isWhiteboardMode && (
             <button onClick={() => setIsSidebarOpen(true)} className="absolute top-4 left-4 z-50 p-2 bg-white rounded-lg shadow-md hover:bg-gray-50 text-gray-500"><Menu size={16} /></button>
         )}

         {isWhiteboardMode ? (
            <div className="relative w-full h-full bg-[#F9F8F6]">
                <Canvas 
                    cards={activeWorkspace.cards}
                    onCardsChange={updateCards}
                    activeTool={activeTool}
                    onToolUsed={() => setActiveTool('SELECT')}
                    scale={scale}
                    onScaleChange={setScale}
                    pan={pan}
                    onPanChange={setPan}
                    isSpacePressed={isSpacePressed}
                />

                {/* Header (Top Right) */}
                <div className="absolute top-6 right-6 z-[50] flex items-center gap-3 no-drag">
                    {/* Breadcrumbs */}
                    <div className="hidden md:flex h-10 px-4 items-center gap-2 rounded-xl bg-white border border-[#5F2427]/10 shadow-sm select-none">
                        <span className="text-[13px] font-semibold text-[#5F2427] max-w-[120px] truncate opacity-70">
                            {realNode ? nodes[realNode.parentId || '']?.name || 'Workspace' : 'Workspace'}
                        </span>
                        <span className="text-[#FFD753] font-bold text-[14px]">/</span>
                        {isRenamingTitle ? (
                            <input autoFocus value={titleInputValue} onChange={(e) => setTitleInputValue(e.target.value)} onBlur={() => { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); }} onKeyDown={(e) => { if(e.key === 'Enter') { if(titleInputValue.trim()) handleUpdateNode(activeNodeId, { name: titleInputValue.trim() }); setIsRenamingTitle(false); } if(e.key === 'Escape') setIsRenamingTitle(false); }} className="text-[13px] font-bold text-[#5F2427] bg-transparent border-none outline-none p-0 w-[160px] focus:ring-0" />
                        ) : (
                            <span onDoubleClick={(e) => { e.stopPropagation(); setIsRenamingTitle(true); setTitleInputValue(displayedNode.name); }} className="text-[13px] font-bold text-[#5F2427] max-w-[160px] truncate cursor-text hover:bg-[#5F2427]/5 px-1 -mx-1 rounded transition-colors">{displayedNode.name}</span>
                        )}
                    </div>

                    {/* Zoom / Undo / Redo Control Bar */}
                    <div className="h-10 flex items-center rounded-xl bg-white border border-[#5F2427]/10 shadow-sm overflow-hidden select-none">
                        <div className="px-3 h-full flex items-center justify-center bg-[#3A5C34]/5">
                            <span className="text-[13px] font-bold text-[#3A5C34] min-w-[32px] text-center">
                                {Math.round(scale * 100)}%
                            </span>
                        </div>

                        {/* Divider */}
                        <div className="w-px h-full bg-[#3A5C34]/10" />

                        <button 
                            onClick={handleUndo} 
                            disabled={history.length === 0}
                            className="h-full px-3 flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 active:bg-[#3A5C34]/20 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                        >
                            <Undo2 size={18} />
                        </button>

                        {/* Divider */}
                        <div className="w-px h-full bg-[#3A5C34]/10" />

                        <button 
                            onClick={handleRedo}
                            disabled={future.length === 0}
                            className="h-full px-3 flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 active:bg-[#3A5C34]/20 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                        >
                            <Redo2 size={18} />
                        </button>
                    </div>

                    {/* Exit Button */}
                    <button onClick={handleExitWhiteboard} className="h-10 w-10 rounded-xl bg-[#FCCAE2] shadow-sm border border-[#5F2427]/10 flex items-center justify-center text-[#5F2427] hover:bg-[#ffb4d6] hover:scale-105 active:scale-95 transition-all">
                        <LogOut size={18} strokeWidth={2.5} className="ml-0.5" />
                    </button>
                </div>

                {/* Left Hover Drawer Trigger & Button (Standard Position) */}
                <div 
                    className="absolute top-0 left-0 bottom-0 w-3 z-30" 
                    onMouseEnter={() => setIsDrawerOpen(true)}
                />

                {/* Explicit Open Drawer Button - Standard Style */}
                {!isDrawerOpen && (
                    <button 
                        onClick={() => setIsDrawerOpen(true)}
                        className="absolute top-6 left-6 z-[40] w-10 h-10 bg-[#3A5C34] rounded-xl shadow-[0_4px_12px_rgba(0,0,0,0.08)] border border-[#FFD753]/10 text-[#FFD753] flex items-center justify-center hover:scale-105 hover:bg-[#2d4a29] active:scale-95 transition-all"
                        title="Add Tools"
                    >
                        <Plus size={20} />
                    </button>
                )}

                {/* --- TOOL DRAWER (RESTORED PREMIUM DESIGN) --- */}
                <div 
                    className={`absolute inset-y-0 left-0 z-50 flex transition-transform duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] ${isDrawerOpen ? 'translate-x-0' : '-translate-x-full'}`} 
                    onMouseLeave={() => setIsDrawerOpen(false)}
                >
                    <div className="w-[320px] h-full bg-white/95 backdrop-blur-xl shadow-2xl flex flex-col border-r border-gray-200/50">
                        {/* Drawer Header */}
                        <div className="p-5 bg-white/50 z-10 pt-8 sticky top-0 backdrop-blur-md flex flex-col gap-3">
                             <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                                <input placeholder="Find a tool..." className="w-full bg-gray-50 border-none rounded-xl pl-9 pr-4 py-2.5 text-[13px] focus:ring-2 focus:ring-[#3A5C34]/20 placeholder-gray-400 transition-all" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
                             </div>
                        </div>

                        {/* Tool Categories (Filtered List) */}
                        <div className="flex-1 overflow-y-auto p-4 space-y-6 pb-20 no-scrollbar">
                            {displayedTools.length > 0 ? (
                                displayedTools.map((category, idx) => (
                                    <div key={idx} className="animate-in slide-in-from-left-4 duration-300" style={{ animationDelay: `${idx * 75}ms` }}>
                                        <h3 className="text-[11px] font-bold text-gray-400 uppercase tracking-widest mb-2 px-2">{category.category}</h3>
                                        <div className="space-y-1">
                                            {category.items.map((tool, tIdx) => (
                                                <ToolButton 
                                                    key={tIdx} 
                                                    icon={tool.icon} 
                                                    label={tool.label} 
                                                    subLabel={tool.subLabel} 
                                                    bgColor={tool.bgColor} 
                                                    iconColor={tool.iconColor} 
                                                    onClick={tool.action} 
                                                />
                                            ))}
                                        </div>
                                    </div>
                                ))
                            ) : (
                                <div className="flex flex-col items-center justify-center h-40 text-gray-400 text-center px-4">
                                    <Archive size={32} className="mb-2 opacity-20" />
                                    <p className="text-[13px] font-medium">No tools found</p>
                                    <p className="text-[11px]">Try searching for something else.</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Bottom Left Tabs */}
                <div className="absolute bottom-6 left-6 z-40 flex items-end justify-start pointer-events-none">
                    <div className="pointer-events-auto flex items-center h-10 bg-white rounded-xl shadow-sm border border-[#5F2427]/10 overflow-hidden max-w-[calc(100vw-400px)]">
                        <div className="flex items-center overflow-x-auto no-scrollbar h-full">
                            {workspaces.map(ws => {
                                const isActive = activeWorkspaceId === ws.id;
                                const { text: textColor, bg: activeColor } = getTabTheme(ws.color);
                                const bgOpacity = isActive ? '1A' : (hoveredTabId === ws.id ? '0D' : '00');
                                return (
                                    <div key={ws.id} className="relative group h-full flex flex-shrink-0">
                                        <div 
                                            onClick={() => !editingTabId && setActiveWorkspaceId(ws.id)}
                                            onDoubleClick={(e) => { e.stopPropagation(); e.preventDefault(); setEditingTabId(ws.id); setEditTabName(ws.name); setColorPickerState(null); }}
                                            onMouseEnter={() => setHoveredTabId(ws.id)}
                                            onMouseLeave={() => setHoveredTabId(null)}
                                            className={`px-4 h-full flex items-center gap-2 text-[13px] transition-all duration-200 border-r border-gray-100 select-none min-w-[100px] cursor-pointer ${isActive ? 'font-bold' : 'font-medium text-gray-500'}`}
                                            style={{ color: (isActive || hoveredTabId === ws.id) ? textColor : undefined, backgroundColor: (isActive || hoveredTabId === ws.id) ? `${activeColor}${bgOpacity}` : 'transparent' }}
                                        >
                                            {editingTabId === ws.id ? (
                                                <input autoFocus value={editTabName} onChange={(e) => setEditTabName(e.target.value)} onBlur={() => { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); }} onKeyDown={(e) => { if(e.key === 'Enter') { if (editingTabId && editTabName.trim()) updateTabName(editingTabId, editTabName.trim()); setEditingTabId(null); } if(e.key === 'Escape') setEditingTabId(null); }} className="bg-transparent border-none outline-none p-0 w-[100px] text-inherit font-inherit" />
                                            ) : (
                                                <span className="truncate max-w-[120px]">{ws.name}</span>
                                            )}
                                            {isActive && !editingTabId && <div onClick={(e) => toggleColorPicker(e, ws.id)} className="p-0.5 rounded hover:bg-black/5 cursor-pointer ml-1"><ChevronDown size={10} strokeWidth={3} /></div>}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                        <button onClick={addTab} className="w-10 h-full flex items-center justify-center text-[#3A5C34] hover:bg-[#3A5C34]/10 transition-colors border-l border-[#5F2427]/5 flex-shrink-0"><Plus size={18} strokeWidth={2.5} /></button>
                    </div>
                </div>

                {/* Color Picker Popover */}
                {colorPickerState && (
                    <div onClick={(e) => e.stopPropagation()} className="absolute bg-white/80 backdrop-blur-xl border border-white/40 p-3 rounded-2xl shadow-xl flex flex-col gap-3 w-56 z-[100]" style={{ left: colorPickerState.x, top: colorPickerState.y - 12, transform: 'translate(-50%, -100%)' }}>
                        <div className="grid grid-cols-7 gap-1.5">
                            {TAB_COLORS.map(c => <button key={c} onClick={() => updateTabColor(colorPickerState!.id, c)} className="w-6 h-6 rounded-full shadow-sm flex items-center justify-center transition-transform hover:scale-110 active:scale-95 border border-black/5" style={{ backgroundColor: c }}>{workspaces.find(w => w.id === colorPickerState!.id)?.color === c && <Check size={12} className="text-white drop-shadow-md" />}</button>)}
                        </div>
                        <div className="h-px bg-black/5 w-full my-0.5"></div>
                        <button onClick={() => deleteTab(colorPickerState!.id)} className="flex items-center gap-2 px-2 py-1.5 text-red-500 hover:bg-red-50 rounded-lg text-[13px] font-medium transition-colors w-full"><Trash2 size={14} /><span>Delete Tab</span></button>
                    </div>
                )}

                {/* Drawing Toolbar */}
                {['PEN', 'HIGHLIGHTER', 'ERASER', 'LASSO'].includes(activeTool) && (
                    <DrawingToolbar activeTool={activeTool} onToolChange={setActiveTool} onClose={() => setActiveTool('SELECT')} />
                )}
            </div>
         ) : (
            <PageView 
                node={displayedNode}
                childNodes={displayedChildren}
                onNavigate={handleNavigate}
                onCreateWhiteboard={() => handleCreateNode('whiteboard', activeNodeId === 'root' ? null : activeNodeId)}
                onCreateFolder={() => handleCreateNode('folder', activeNodeId === 'root' ? null : activeNodeId)}
                onToggleFavorite={id => { soundService.play('toggle'); setNodes(prev => ({ ...prev, [id]: { ...prev[id], isFavorite: !prev[id].isFavorite } })) }}
                onUpdateNode={handleUpdateNode}
                onReorderNode={handleReorderNode}
                tourCompleted={userProfile?.tour_completed}
                onDismissTour={handleDismissTour}
            />
         )}
      </div>
    </div>
  );
}

