export const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

/**
 * Persistence Strategy:
 * We store the entire application state in a single JSONB column per user.
 * Table: 'user_files'
 * Columns: 'user_id' (uuid, primary key), 'data' (jsonb)
 */

export interface AppData {
  nodes: Record<string, FileSystemNode>;
  activeNodeId: string;
  activeWorkspaceId?: string;
  lastUpdated?: string;
}

// --- DATA PERSISTENCE ---

export const saveAppData = async (appData: AppData) => {
  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return;

    const { error } = await supabase
      .from('user_files')
      .upsert({ 
        user_id: session.user.id, 
        data: appData,
        updated_at: new Date().toISOString()
      });

    if (error) {
      console.warn('Supabase Save Error:', error.message);
      throw error;
    }
  } catch (e) {
    console.error('Unexpected Supabase Error:', e);
    throw e;
  }
};

export const loadAppData = async (): Promise<AppData | null> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();
    if (!session) return null;

    const { data, error } = await supabase
      .from('user_files')
      .select('data')
      .eq('user_id', session.user.id)
      .single();

    if (error) {
      if (error.code !== 'PGRST116') {
        console.log('Supabase Load Status:', error.message);
      }
      return null;
    }

    const loadedData = data?.data;

    // Migration/Compatibility Check
    // If the data is the old "Record<string, Node>" format, wrap it
    if (loadedData && !loadedData.nodes && Object.keys(loadedData).some(k => k.startsWith('folder') || k === 'root')) {
        return {
            nodes: loadedData as Record<string, FileSystemNode>,
            activeNodeId: 'root',
            activeWorkspaceId: 'tab-1'
        };
    }

    return loadedData as AppData;
  } catch (e) {
    console.error('Unexpected Supabase Load Error:', e);
    return null;
  }
};

// Deprecated but kept for type safety if needed elsewhere temporarily
export const saveNodesToSupabase = async (nodes: Record<string, FileSystemNode>) => {
    await saveAppData({ nodes, activeNodeId: 'root' });
};
export const loadNodesFromSupabase = async () => {
    const appData = await loadAppData();
    return appData?.nodes || null;
};

